INSERT INTO `penyakit` (`id_penyakit`, `kode_penyakit`, `nama_penyakit`, `det_penyakit`, `srn_penyakit`, `gambar`) VALUES
(1, 'P1', 'Penyakit kuning', 'Tanaman yang terserang akan menunjukkan gejala berupa daun tampak berwarna kuning, sedangkan tulang-tulang daun tetap berwarna hijau.', 'Berikan Master Coliprim dosis: 1 gr/1 ltr air selama 3-4 hari (1/2 hari) berturut-turut. setelah itu berikan Master Vit-Stress selama 3-4 hari untuk membantu proses penyembuhan.', '1.jpg'),
(2, 'P2', 'Penyakit busuk pangkal batang', 'Penyakit busuk pangkal batang (BPB) merupakan salah satu kendala produksi lada di Indonesia dan sangat ditakuti petani karena dapat menyebabkan kematian tanaman secara cepat.', 'Berikan Master Kolericid dosis: 1 gr/1 ltr air selama 3-4 hari berturut-turut. berikan Master Vit-Stress dosis: 1 gr/3 ltr air untuk membantu proses penyembuhan.', '1.jpg'),
(3, 'P3', 'Penyakit Keriting atau kerdil', 'Penyakit Avian Influenza, disebut juga penyakit Fowl Plaque. Pertama kali terjadi di Italia sekitar tahun 1800. Selanjutnya menyebar luas sampai tahun 1930, setelah itu menjadi sporadis dan terlokalisasi terutama di timur tengah.', 'Tidak ada obat.\r\nDianjurkan untuk disingkirkan dan dimusnakan dengan cara dibakar dan bangkainya dikubur.', '03FluBurung.jpg'),
(4, 'P4', 'Penyakit Jamur Pirang', 'Penyakit Newcastle Disease disebut juga Pseudovogel pest Rhaniket, Pheumoencephalitis, Tortor Furrens, dan di Indonesia popular dengan sebutan tetelo. Penyakit ini pertama kali ditemukan oleh Doyle pada tahun 1927, didaerah Newcastle on Tyne, Inggris', 'Vaksinasi harus dilakukan untuk memperoleh kekebalan. Jenis vaksin yang kami gunakan adalah ND Lasota yang kami beli dari PT. SHS. Vaksinasi ND yang pertama, kami lakukan dengan cara pemberian melalui tetes mata pada hari ke 2. Untuk berikutnya pemberian vaksin kami lakukan dengan cara suntikan di intramuskuler otot dada.', '04Tetelo.jpg'),
(5, 'P5', 'Penyakit Benang Putih dan Rambut ', 'Penyakit Fowl Typhoid dikenal sebagai penyakit tipus ayam, tergolong penyakit menular.', 'Berikan Neo Terramycin dosis: 2 sendok teh/3,8 ltr air selama 3-4 hari berturut-turut.', '05Tipus Ayam.jpg'),
(6, 'P6', 'Penyakit Busuk Akar', 'Coccidosis merupakan penyakit menular yang ganas, dikalangan para peternak ayam disebut juga penyakit berak darah. Penyakit ini ditemukan pada tahun 1674.', 'Berikan Master Coliprim dosis: 1gr/1 ltr air selama 3-4 hari (1/2 hari) berturut-turut. setelah pengobatan berikan Vitamin Master Vit-Stress dosis: 1gr/3 ltr selama 3-4 hari berturut-turut.', '06Berak Darah.jpg'),
(7, 'P7', 'Penyakit Jaring Laba â Laba dan Rambut Ekor Kuda', 'Penyakit Gumboro, disebut juga Infectious Bursal Disease. Pertama kali ditemukan dan dilaporkan pada tahun 1975 oleh Dr. Csgrove di daerah Gumboro, Deleware, Amerika Serikat.', 'Tidak ada obat.\r\nAir gula 30-50 gr/ltr air dan ditambah Master Vit-Stress dosis: 1 gr/2 ltr air untuk meningkatkan kondisi tubuh.', '07Gumboro.jpg'),
(8, 'P8', 'Penyakit Septobasidium sp', 'Penyakit Infectious Coryza disebut juga Infectious Cold, Snot, Rhinitis, Roup atau yang populer disebut salesma ayam.', 'Berikan Master Cyprosyn-Plus dosis: 1 gr/1 ltr air selama 3-4 hari berturut-turut. selama pengobatan berikan vitamin Master Vit-Stress dosis: 1 gr/3 ltr air untuk membantu proses pengobatan.', '08Snot.jpg'),
(9, 'P9', 'Penyakit antraknosa', 'Penyakit Infectious Bronchitis pertama kali ditemukan pada tahun 1930 dan penyakit ini mulai menjadi wabah sejak tahun 1940. Pada tahun 1950 penyakit Infectious Bronchitis sudah dapat dikendalikan dengan efektif.', 'Tidak ada obat.\r\nBerikan vitamin Master Vit-Stress dosis: 1 gr/1 ltr air untuk memperbaiki kondisi tubuh', '09IB.jpg');

