INSERT INTO `post` (`kode_post`, `nama_post`, `det_post`, `srn_post`, `gambar`) VALUES
(14, 'Berak Kapur', '<p>Salah satu penyakit pada unggas adalah penyakit Berak Kapur (Pullorum Disease). Pullorum merupakan suatu penyakit infeksius pada unggas, terutama anak ayam dan anak kalkun, yang ditularkan melalui telur (Tabbu, 2000).&nbsp;&nbsp;Penyakit Berak Kapur (Pullorum Disease) biasanya ditemukan dalam bentuk sistemik akut pada anak ayam, tetapi lebih sering bersifat local dan kronis pada ayam dewasa.</p>\r\n\r\n<p><strong>DESKRIPSI : </strong></p>\r\n\r\n<p>Penyakit ini banyak menyerang anak ayam. Terutama umur 1&mdash;10&nbsp; hari. Kebanyakan yang kena lemah dan mati muda. Pada ayam dewasa tidak terlihat gejala - gejala sakit. Ayam yang sembuh&nbsp; menjadi pembawa sifat dan seumur&nbsp; hidupnya mengeluarkan bibit penyakit.</p>\r\n\r\n<p><strong>ETIOLOGI :</strong></p>\r\n\r\n<p>Salmonella pullorum</p>\r\n\r\n<p>Bentuk batang, Gram negatif, non motil, tidak berspora, fakultatif aerob.</p>\r\n\r\n<p><strong>GEJALA: </strong></p>\r\n\r\n<ol>\r\n	<li>Anak ayam : Nafsu makan berkurang. Kotoran encer berwarna putih berlendir dan banyak melekat pada daerah anus. Ayam terlihat pucat, lemah, kedinginan dan suka bergerombol mencari tempat hangat. Sayap tampak kusut dan menggantung, jengger pucat dan berkerut berwarna keabu-abuan.</li>\r\n	<li>Ayam dewasa : Pembengkakan Pada Lutut, Menurunnya kesuburan dan daya tetas, depresi, anemia dan kotoran encer warna kuning/putih.</li>\r\n</ol>\r\n\r\n<p><a href=\"http://localhost/spkayam/gambar/posting/Berak Kapur.jpg\"><img alt=\"PENYAKIT BERAK KAPUR (PULLORUM DISEASE) PADA AYAM\" src=\"http://localhost/spkayam/gambar/posting/Berak Kapur.jpg\" style=\"height:199px; width:267px\" /></a></p>\r\n\r\n<blockquote>\r\n<p><small>Gambar 1 = Tampak kotoran Ayam berwarna putih berceceran</small></p>\r\n</blockquote>\r\n\r\n<p><a href=\"http://localhost/spkayam/gambar/posting/Berak Kapur 2.jpg\"><img alt=\"PENYAKIT BERAK KAPUR (PULLORUM DISEASE) PADA AYAM\" src=\"http://localhost/spkayam/gambar/posting/Berak Kapur 2.jpg\" style=\"height:341px; width:268px\" /></a></p>\r\n\r\n<blockquote>\r\n<p><small>Gambar 2 = Pembengkakan pada lutut Ayam dewasa, tetapi bukan gejala spesifik</small></p>\r\n</blockquote>\r\n\r\n<p><strong>CARA PENULARAN :</strong></p>\r\n\r\n<p>Secara kongenital/vertikal : dari induk ke anak, saat telur di ovarium, oviduk atau kloaka.</p>\r\n\r\n<p>Secara horisontal :</p>\r\n\r\n<ol>\r\n	<li>oral, melalui pakan, air minum dan litter yg terkontaminasi.</li>\r\n	<li>aerogen/udara pernapasan: dalam mesin tetas melalui: debu, bulu-bulu, anak ayam dan pecahan cangkang</li>\r\n</ol>\r\n\r\n<p><strong>PERUBAHAN PASCA MATI :</strong></p>\r\n\r\n<ol>\r\n	<li>hati membesar, haemorrhagi, gumpalan darah di rongga perut.</li>\r\n	<li>jantung dilatasi, noduli putih keabuan</li>\r\n	<li>perikardium : bengkak, perikarditis, cairan fibrinous</li>\r\n	<li>limfa, ginjal membesar, jejas nekrotis.</li>\r\n	<li>reproduksi betina : folikel keriput, kuning telur memadat dan mengkeju</li>\r\n	<li>reproduksi jantan : abses kecil pada testes, penebalan</li>\r\n</ol>\r\n\r\n<p><strong>PENYEBAB :</strong> Bakteri Salmonella pullorum</p>\r\n\r\n<p><strong>KERUGIAN EKONOMI :</strong> Turun produksi telur dan &nbsp;daya tetas, kematian embrio, anak ayam maupun ayam dewasa.</p>\r\n', '<p><strong>Pencegahan: </strong></p>\r\n\r\n<ol>\r\n	<li>Menjaga sanitasi mulai dari mesin penetasan hingga sanitasi kandang</li>\r\n	<li>Melakukan desinfeksi kandang dengan formal dehyde sebanyak 40%.</li>\r\n	<li>Ayam yang terkena penyakit sebaiknya dipisahkan dari kelompoknya, sedangkan ayam yang parah dimusnahkan.</li>\r\n</ol>\r\n\r\n<p><strong>Pengendalian :</strong></p>\r\n\r\n<ol>\r\n	<li>Perusahaan pembibit yg terserang salmonellosis dilarang keluarkan telur tetas, ayam mati ataupun hidup, kecuali untuk diagnosis.</li>\r\n	<li>Ayam yang mati dibakar dan dikubur.</li>\r\n	<li>Uji masal pada unggas di atas 4 bulan, yg positif dimusnahkan.</li>\r\n	<li>Peternakan yg positif mengandung penyakit dilarang lalu lintas orang, kecuali petugas dan orang yg keluar dari peternakan tersebut harus di suci hamakan.</li>\r\n</ol>\r\n\r\n<p><strong>Tindakan: </strong></p>\r\n\r\n<ol>\r\n	<li>Berikan Master Coliprim dosis: 1 gr/1 ltr air selama 3-4 hari (1/2 hari) berturut-turut. setelah itu berikan Master Vit-Stress selama 3-4 hari untuk membantu proses penyembuhan.</li>\r\n	<li>Menyuntikkan antibiotik seperti furozolidon, coccilin, neo terramycin, tetra atau mycomas di dada ayam. pengobatan dapat dilakukan dengan menggunakan preparat sulfonamide.</li>\r\n</ol>\r\n', '01 Berak Kapur.jpg'),
(15, 'Kolera Ayam (Fowl Cholera)', '<p>Kolera unggas (<em>fowl cholera</em>) adalah penyakit menular pada unggas dengan angka kesakitan dan kematian yang tinggi (Akoso, 1993). Penyakit kolera <em>(f</em><em>owl cholera</em><em>)</em> disebabkan oleh bakteri <em>Pasteurella multocida</em> yang merupakan bakteri gram negatif (-), berbentuk ovoid, tidak membentuk spora, menunjukkan struktur bipoler serta kadang-kadang membentuk kapsul yang mengelilingi organisme tersebut. Kemampuan <em>Pasteurella multocida</em> sangat tergantung pada kapsul yang megelilingi organisme tersebut. Apabila kapsul itu hilang maka kemampuan virulensinya juga akan menurun.</p>\r\n\r\n<p><strong>Cara Penularan Penyakit</strong></p>\r\n\r\n<p>Penularan penyakit terjadi secara horizontal dimana ayam sehat tertular dengan ayam sakit melalui peralatan kandang, kotoran hewan maupun oleh pekerjanya sendiri. Menurut Christensen dan Bisgaard (2000), tikus, insekta (terutama lalat) dan burung liar juga berperan dalam penyebarannya. Penyakit kolera unggas (<em>fowl cholera</em>) juga dapat ditularkan melalui udara, pakan, air minum, dan bangkai ayam yang tercemar (Biberstein dan Chung Zee, 1990). Bakteri menginfeksi ke dalam jaringan tubuh melalui saluran pernapasan dan melalui konjungtiva ataupun luka pada permukaan jaringan.&nbsp;</p>\r\n\r\n<p><a href=\"http://localhost/spkayam/gambar/posting/kolera ayam.jpeg\"><img alt=\"\" src=\"http://localhost/spkayam/gambar/posting/kolera ayam.jpeg\" style=\"height:411px; width:337px\" /></a></p>\r\n\r\n<p>Awal mula kuman <em>P. multocida</em> masuk kedalam kandang ternak ayam sulit dideteksi. Tetapi apabila sudah berada di dalam salah satu kelompok/<em>flock</em> maka penyebaran lewat ayam yang terinfeksi sangat mudah terjadi. Rute penularan infeksi kolera unggas dapat terjadi melalui ingesti kuman dari air atau makanan yang tercemar, inhalasi udara yang tercemar dan penularan langsung dari ayam ke ayam lainnya. Lingkungan sekitar dapat tercemar kuman <em>P. multocida</em> dari peralatan dan ayam-ayam yang mati pada infeksi sebelumnya. Selama ini, penyebab utama infeksi pada satu kandang/flock berasal dari infeksi sebelumnya (kronis). Selain itu pekerja kandang juga sumber penyebaran, baik melalui ludah dan ingus yang sembarangan di sekitar kandang. Peralatan dan pakan yang tercemar dapat menjadi sumber penularan apabila tidak dilakukan desinfeksi dan cara penyimpanan yang baik. Secara ringkas, pada saat kuman <em>P. multocida</em> berhasil masuk kedalam flock maka infeksi akan segara terjadi dengan konsentrasi kuman di saluran pernafasan atas, mulai dari rongga mulut (paruh), trakea dan sekitar mata.</p>\r\n\r\n<p>Penularan penyakit kolera dari manusia ke ayam broiler yaitu manusia dapat terinfeksi oleh <em>Pasteurella multocida</em> ataupun merupakan sumber infeksi bagi unggas melalui leleran dari hidung ataupun mulut. Bakteri ini biasanya masuk kedalam jaringan melalui membrana mukosa laring atau saluran pernafasan bagian atas, tetapi dapat juga masuk melalui konjungtiva ataupun luka pada permukaan jaringan (Tabbu, 2000).</p>\r\n\r\n<p><strong>Masa Inkubasi dan Tanda &ndash; Tanda Penyakit Kolera</strong></p>\r\n\r\n<p>Penyakit kolera unggas memiliki dua bentuk yaitu akut dan kronik. Bentuk akut ditandai dengan <em>hemoragik-septisemia</em>, disertai angka kematian tinggi, sementara yang kronik sering terlihat adanya gangguan pernafasan, torsikolis, radang sendi, pembengkakan kelopak mata, sinus dan pial. Secara <em>pathologi-anatomi</em> perubahannya terbatas pada saluran pernafasan, termasuk kantong udara dan sinus (Akoso, 1993).</p>\r\n\r\n<p>Setelah terjadi invasi bibit penyakit ke dalam tubuh, maka ayam akan mengalami <em>bacterimia</em> (bakteri sudah beredar ke seluruh pembuluh darah) tahap awal. Masa inkubasi (waktu mulai masuknya bibit penyakit hingga menimbulkan gejala klinis) berlangsung selama 4-9 hari dan umumnya menyerang ayam berumur 3 bulan ke atas. Tanda - tanda <em>bacterimia</em> biasanya ditandai dengan :</p>\r\n\r\n<ol>\r\n	<li>Penurunan nafsu makan pada awalnya ditandai dengan mundurnya waktu habis pakan yang berlanjut dengan menurunnya jumlah konsumsi pakan pada ayam. Apabila ayam menunjukkan penurunan nafsu makan maka peternak harus curiga terhadap indikasi penyakit tertentu atau memang hanya dikarenakan stres.</li>\r\n	<li>Ayam tampak lesu dan mengantuk</li>\r\n	<li>Dengan adanya penurunan nafsu makan dan minum maka akan berdampak pada kondisi tubuh yang lemah.</li>\r\n	<li>Demam yang ditandai dengan kloaka kering dan peningkatan suhu badan mencapai 2-3oC.</li>\r\n	<li>Saat kontrol pada malam hari, terkadang akan terdengar suara ngorok disertai sedikit getaran karena adanya lendir.</li>\r\n</ol>\r\n\r\n<p><strong>Dua bentuk penyakit kolera unggas yaitu :</strong></p>\r\n\r\n<p>1.&nbsp;&nbsp;&nbsp; Akut</p>\r\n\r\n<p>Gejala akut kerap kali ditemukan pada beberapa jam sebelum terjadi kematian. Gejala yang tampak adalah penurunan nafsu makan, mengalami kerontokan bulu, diare yang awalnya encer kekuningan dan lama-kelamaan akan berwarna kehijauan disertai mucus (lendir), peningkatan frekuensi pernapasan, daerah muka, jengger dan pial membesar (Akoso, 1993). Menurut Syamsudin (1980) menyatakan kolera unggas akut ditandai oleh adanya kematian mendadak dan mortalitas tinggi. Kematian dapat berkisar antara 0-20%. Selain itu, kejadian penyakit ini dapat menyebabkan penurunan produksi telur dan penurunan berat badan. Kerugian yang lain adalah meningkatnya biaya pengobatan.</p>\r\n\r\n<p><a href=\"http://localhost/spkayam/gambar/posting/kolera ayam 2.jpg\"><img alt=\"\" src=\"http://localhost/spkayam/gambar/posting/kolera ayam 2.jpg\" style=\"height:252px; width:400px\" /></a></p>\r\n\r\n<p>Penyakit akut yang nampak biasanya terkait dengan kerusakan pembuluh darah yang menyebabkan perdarahan. Perubahan yang terlihat berupa perdarahan <em>ptechiae</em> pada berbagai organ visceral terutama pada jantung, hati, paru-paru, lemak jantung maupun lemak abdominal. Selain itu juga sering ditemukan perdarahan berupa <em>ptechiae</em> (bintik-bintik) dan <em>echimosa</em> (lebam) pada mukosa usus. Hal ini disebabkan pecahnya pembuluh darah kapiler akibat aktivitas endotoksin. Hati akan terlihat membesar dan berwarna belang. Pada kasus akut, tidak jarang pula ovarium pada folikel dewasa membubur atau mengalami perdarahan hemorhagi. Apabila kondisi sudah demikian maka terjadi penurunan produksi.</p>\r\n\r\n<p>2.&nbsp;&nbsp;&nbsp; Kronis</p>\r\n\r\n<p>Pada bentuk kronis, dimana penyakit berlangsung lama (berminggu-minggu hingga berbulan-bulan) dengan virulensi bakteri rendah. Gejala yang nampak sehubungan dengan adanya infeksi lokal pada pial, sendi kaki, sayap dan basal otak. Gejala yang terlihat biasanya terjadinya pembengkakkan pada pial, infeksi pada kaki (Akoso, 1993). Menurut Syamsudin (1980) menyatakan kolera unggas kronis ditandai oleh adanya gangguan pernafasan dan syaraf, radang persendian, serta pembengkakan dan warna kebiruan (<em>cyanosis</em>) pada balung (jawer) dan pial.</p>\r\n', '<p><strong>Pencegahan :</strong> Prinsip pencegahan penyakit tersebut adalah :</p>\r\n\r\n<p>1.&nbsp; Mengurangi populasi bibit penyakit di sekitar ayam</p>\r\n\r\n<p>Cara mengurangi bibit penyakit yang ada di sekitar ayam maka harus melakukan langkah yang ditempuh yaitu dengan istirahat kandang, sanitasi dan desinfeksi kandang beserta peralatannya. Istirahat kandang minimal selama 2 minggu dihitung setelah kandang sudah dalam keadaan bersih dan didesinfeksi.</p>\r\n\r\n<p>Di sinilah tujuan istirahat kandang yang sebenarnya sehingga bibit penyakit dapat ditekan seminimal mungkin. Selain dengan istirahat kandang, perlu didukung dengan sanitasi dan desinfeksi secara ketat. Desinfeksi kandang kosong bisa dilakukan dengan menggunakan <em>Sporades, Formades</em> atau <em>Mediklin</em>. 3 hari sebelum <em>chicks in</em>, lakukan kembali penyemprotan kandang beserta peralatannya baik tempat ransum maupun tempat minum dengan menggunakan <em>Medisep</em>.</p>\r\n\r\n<p>2.&nbsp; Mencegah kontak antara bibit penyakit dengan ayam</p>\r\n\r\n<p>Meskipun populasi bibit penyakit di lapangan sudah dalam batas minimal, kita tidak boleh lengah sedikitpun serta tetap harus waspada terhadap penularan penyakit karena sumber penyakit tersebut dapat datang sewaktu-waktu, kapanpun dan dimanapun tanpa permisi. Upaya untuk mendukung langkah tersebut maka perlu dilakukan pencegahan kontak antara bibit penyakit dengan ayam. Langkah pencegahan tersebut dengan cara :</p>\r\n\r\n<ul>\r\n	<li>Mengatur lalu lintas karyawan, pekerja, tamu, kendaraan, hewan piaraan maupun hewan liar yang bisa menjadi sumber penularan.</li>\r\n	<li>Pemeriksaan sumber-sumber air minum karena tidak menutup kemungkinan bibit penyakit masuk melalui air minum. Memberikan antiseptik (Antisep<strong>, </strong>Neo Antisep<strong> </strong>atau<strong> </strong>Medisep) minimal 3x seminggu terutama jika saluran air menggunakan pipa pralon panjang.</li>\r\n	<li>Transportasi dan penyimpanan pakan ransum harus benar.</li>\r\n	<li>Pemberantasan vektor pembawa penyakit seperti tikus dan lalat dengan menggunakan insektisida. Melakukan kontrol yang teratur dan terprogram terhadap rodentia yang berkeliaran di kandang. Berdasarkan pengalaman di lapangan menunjukkan bahwa vektor tersebut merupakan sumber penularan yang cukup tinggi. Bakteri <em>P. multocida</em> yang umum ditemukan pada rongga mulut pada berbagai hewan seperti tikus, mencit, anjing dan kucing. Kucing dan tikus diduga sebagai hewan utama yang membawa bakteri ini ke peternakan unggas (Glisson, 2002).</li>\r\n</ul>\r\n\r\n<p>3.&nbsp; Meningkatkan daya tahan tubuh ayam</p>\r\n\r\n<p>Ketahanan tubuh ayam paling utama ditentukan oleh faktor ransum yang didukung dengan kondisi lingkungannya. Melakukan monitoring terhadap konsumsi ransum maka secara tidak langsung hal tersebut merupakan salah satu upaya dalam meningkatkan ketahanan tubuh ayam. Daya tahan tubuh ayam akan menjadi lebih baik pada lingkungan dengan kadar amonia rendah, tidak berdebu, cukup oksigen, temperatur dan kelembaban sesuai serta tidak <em>over crowded</em> (kepadatan berlebih), maka yang harus diperhatikan adalah suhu dan kelembabannya, ventilasi kandang serta kualitas litter atau sekam.</p>\r\n\r\n<p>Usaha untuk meningkatkan daya tahan tubuh maka dapat dilakukan pemberian multivitamin berupa <em>Fortevit</em> maupun <em>Vita</em><em>s</em><em>tress</em> yang dapat diberikan melalui air minum. Selain meningkatkan daya tahan tubuh, vitamin juga berfungsi dalam membantu pertumbuhan dan mengatasi stress, mencegah penyakit akibat kekurangan vitamin serta mampu memperbaiki efisiensi ransum.</p>\r\n\r\n<ol>\r\n	<li>Apabila menggunakan kandang litter sebaiknya litter tetap kering.</li>\r\n	<li>Mengganti air minum setiap hari.</li>\r\n	<li>Mencuci tempat pakan dan tempat minum minimal 2 kali sehari.</li>\r\n</ol>\r\n\r\n<p>Percobaan untuk pengendalian terhadap kolera ayam dengan cara vaksinasi dimulai oleh Pasteur yang menggunakan biakan yang diatenuasi. Penelitian selanjutnya menunjukkan bahwa untuk mendapatkan derajat perlindungan yang maksimum adalah penting menggunakan galur/strain yang berkapsul yang antigennya berhubungan dengan serotipe penyebab penyakit (Eli, 1985). Pencegahan penyakit ini juga dapat dilakukan dengan memperhatikan pelaksanaan sanitasi yang baik dan mengadakan vaksinasi pada ayam petelur umur 2-3 bulan (Hofstad <em>et al.,</em> 1984).</p>\r\n\r\n<p><strong>Program Vaksinasi :</strong></p>\r\n\r\n<p>Sebelum pelaksanaan vaksinasi, perlu diperhatikan faktor-faktor yang dapat mempengaruhi keberhasilan progr am vaksinasi antara lain :</p>\r\n\r\n<ol>\r\n	<li>Vaksin harus dirawat dan disimpan dalam keadaan sehat dan tidak dalam kondisi stress.</li>\r\n	<li>Ayam yang akan divaksin harus dalam keadaan sehat dan tidak dalam kondisi stress.</li>\r\n	<li>Keadaan nutrisi ayam cukup baik.</li>\r\n	<li>Keadaan sanitasi kandang dan lingkungan baik.</li>\r\n	<li>Pelaksanaan vaksinasi dalam waktu dan umur yang tepat.</li>\r\n	<li>Peralatan untuk vaksinasi dalam keadaan baik dan steril.</li>\r\n</ol>\r\n\r\n<p>Vaksinasi terhadap kolera unggas dilakukan pada ayam umur 6-8 minggu dan diulang sewaktu umur 8-10 minggu. Vaksinasi tidak disarankan untuk dilakukan kecuali bila jelas diketahui terjadi kasus penyakit ini. Antibotika dapat dipergunakan untuk pengobatan adalah <em>stertomisin, klorafenikol</em> dan <em>teramisin</em>. Dapat pula menggunakan preparat sulfa dalam air minum atau pakan (Akoso, 1993).</p>\r\n\r\n<p>Vaksinasi terhadap kolera ayam dengan vaksin inaktif ataupun aktif kadang kadang dilakukan di peternakan dengan kasus kolera yang sulit diatasi dengan praktek manajemen ketat ataupun pada daerah dengan kejadian kolera yang bersifat endemik. Vaksin kolera biasanya diberikan sekitar umur 13 minggu. Hasil vaksin pada kolera biasanya belum memberikan hasil yang memuaskan sehingga tindakan tersebut harus selalu didukung oleh praktek manajemen yang ketat (Tabbu, 2000).</p>\r\n\r\n<p><strong>Pengobatan:</strong></p>\r\n\r\n<p>Pengobatan dapat dilakukan dengan berbagai antibakteri atau antibiotik dengan hasil yang berbeda, karena <em>Pasteurella multocida</em> mempunyai banyak <em>serotipe</em> yang mungkin mempunyai reaksi yang berbeda terhadap berbagai agen kemoterapeutik jenis sulfa, antibiotik, ataupun kelompok flumekuin dan kuinolon mempunyai efektifitas berbeda terhadap pengobatan kolera unggas (Tabbu, 2000).</p>\r\n\r\n<p>Antibiotika yang dapat dipergunakan untuk pengobatan adalah streptomisin, kloramfenikol dan teramisin. Dapat pula menggunakan preparat sulfa dalam air minum atau pakan (Akoso, 1993). Menurut Hofstad <em>et al.,</em> (1984) menyatakan Pengobatan dapat dilakukan dengan menggunakan obat sediaan sulfa dan antibiotika seperti sulfadimetoksin, sulfametazin, tetrasiklin, eritromisin, streptomisin, dan novobiosin.</p>\r\n\r\n<p><strong>Pengobatan pada ayam terserang kolera diantaranya :</strong></p>\r\n\r\n<p>1.&nbsp; Preparat sulfa :</p>\r\n\r\n<ul>\r\n	<li>Sulfaquinoxalin 0.05% dalam air minum.</li>\r\n	<li>Sulfametasin dan sodium sulfametasin 0.5-1.0% dalam makanan atau 0.1% dalam air minum.</li>\r\n	<li>Sulfamerasin 0.5% dalam makanan atau 0.2% dalam air minum. Pemberian per oral dengan dosis 120mg/kg bb.</li>\r\n</ul>\r\n\r\n<p>2.&nbsp; Antibiotika</p>\r\n\r\n<ul>\r\n	<li>Stretomycin dapat mencegah kematian bila diberikan pada awal infeksi.</li>\r\n	<li>Chloramphenicol.</li>\r\n	<li>Teramisin 25mg/kg bb.</li>\r\n</ul>\r\n', '02 Kolera Ayam.jpg'),
(16, 'Flu Burung (Avian Influenza)', '<p>Flu burung atau dalam bahasa Inggris dikenal dengan avian flu atau avian influenza (AI) adalah penyakit menular yang disebabkan virus influenza A sub tipe H5N1 yang biasanya menyerang unggas tetapi juga dapat menyerang manusia. Virus ini termasuk family Orthomyxoviridae dan memiliki diameter 90-120 nanometer.Virus avian influenza ini menyerang alat pernapasan, pencernaan dan system saraf pada unggas.</p>\r\n\r\n<p>Secara normal, virus tersebut hanya menginfeksi ternak unggas seperti ayam, kalkun dan itik, akan tetapi tidak jarang dapat menyerang spesies hewan tertentu selain unggas misalnya babi, kuda, harimau, macan tutul dan kucing. Walaupun hampir semua jenis unggas dapat terinfeksi virus yang terkenal sangat ganas ini, tetapi diketahui yang lebih rentan adalah jenis unggas yang diternakkan secara massal.</p>\r\n\r\n<p><strong>Ciri Virus:</strong></p>\r\n\r\n<p><strong><a href=\"http://localhost/spkayam/gambar/posting/flu burung.jpeg\"><img alt=\"\" src=\"http://localhost/spkayam/gambar/posting/flu burung.jpeg\" style=\"height:277px; width:444px\" /></a></strong></p>\r\n\r\n<p>Virus influensa pada manusia dan binatang ada beberapa tipe yaitu tipe A, tipe B dan Tipe C. Pada manusia virus A dan virus B dapat menjadi penyebab wabah flu yang cukup luas, sementara virus C menyebar secara periodic, ringan dan tidak menyebabkaxn wabah. Virus influensa tipe A dapat berubah-ubah bentuk (Drift, Shift), dan dapat menyebabkan epidemic dan pandemi.</p>\r\n\r\n<p>Virus A mempunyai permukaan yang terdapat dua glikoprotein, yaitu hemaglutinin (H) dan neuraminidase (N).Untuk mengklasifikasikannya secara rinci, maasing-masing tipe virus itu dibagi lagi menjadi subtipe berdasarkan kelompok H dan N, yaitu H1 sampai H15 dan N1 sampai N9. Perbedaan H merupakan dasar subtype. Influensa pada manusia sejauh ini disebabkan virus H1N1, H2N2 dan H3N2 serta virus avian H5N1, H9N2 dan H7N7.</p>\r\n\r\n<p>Strain&nbsp; yang&nbsp; sangat&nbsp; virulen atau ganas&nbsp; dan&nbsp; menyebabkan&nbsp; flu&nbsp; burung&nbsp; adalah&nbsp; dari subtipe A&nbsp; H5N1. Virus tersebut dapat bertahan hidup di air sampai 4 hari pada suhu &nbsp;220&nbsp; C&nbsp; dan&nbsp; lebih&nbsp; dari&nbsp; 30&nbsp; hari&nbsp; pada&nbsp; 100&nbsp; C.&nbsp; Virus&nbsp; akan&nbsp; mati&nbsp; pada&nbsp; pemanasan&nbsp; 600&nbsp; C selama&nbsp; 30&nbsp; menit&nbsp; atau&nbsp; 560&nbsp; C&nbsp; selama&nbsp; 3&nbsp; jam.</p>\r\n\r\n<p><strong>Jalur Penularan:</strong></p>\r\n\r\n<p>Virus Avian Influenza (AI) ditularkan melalui air liur, ingus, dan kotoran unggas.Penularan pada manusia terjadi karena kontak langsung dengan unggas yang terinfeksi virus tersebut. Selain itu, dapat terjadi melalui kendaraan yang mengangkut binatang itu, kadang, alat-alat peternakan, pakan ternak, pakaiaan, tinja ternak dan sepatu para peternak yang langsung mengenai unggas yang sakit, juga pada saat jual-beli ayam hidup dipasar, dan mekanisme lainnya.</p>\r\n\r\n<p>Penularan penyakit ini dapat terjadi melalui udara (air borne) dan melalui kontak langsung dengan unggas sakit atau kontak dengan bahan bahan infeksius seperti tinja, urin, dan sekret saluran napas unggas sakit.</p>\r\n\r\n<p><strong>1. </strong><strong>Penularan antar ternak unggas</strong></p>\r\n\r\n<p>Seekor unggas yang terinfeksi virus H5N1 akan menularkannya dalam waktu singkat. Jika semua unggas peliharaan memiliki daya tahan yang bagus&nbsp; maka infeksi tidak akan menyebabkan kematian, dengan kata lain virus tidak aktif. Sebaliknya, jika kondisi unggas berada dalam kondisi buruk maka flu burung dapat mematikan.</p>\r\n\r\n<p>Secara singkat, penyakit flu burung dapat ditularkan dari unggas ke unggas lain atau dari peternakan ke peternakan lainnya dengan cara sebagai berikut:</p>\r\n\r\n<ul>\r\n	<li>Kontak langsung dari unggas terinfeksi dengan hewan yang peka.</li>\r\n	<li>Melalui lendir yang berasal dari hidung dan mata.</li>\r\n	<li>Melalui kotoran (feses) unggas yang terserang flu burung.</li>\r\n	<li>Lewat manusia melalui sepatu dan pakaian yang terkontaminasi dengan virus.</li>\r\n	<li>Melalui pakan, air, dan peralatan kandang yang terkontaminasi.</li>\r\n	<li>Melalui udara karena memiliki peran penting dalam penularan dalam satu kandang, tetapi memiliki peran terbatas dalam penularan antar kandang.</li>\r\n	<li>Melalui unggas air yang dapat berperan sebagai sumber (reservoir) virus dari dalam saluran intestinal dan dilepaskan lewat kotoran.</li>\r\n</ul>\r\n\r\n<p><strong>2. Penularan dari ternak ke manusia </strong></p>\r\n\r\n<p>Faktor yang memengaruhi penularan flu burung dari ternak ke manusia adalah jarak dan intensitas dalam aktivitas yang berinteraksi dengan kegiatan peternakan. Semakin dekat jarak peternakan yang terkena wabah virus dengan lingkungan manusia maka peluang untuk menularnya virus bisa semakin besar. Penularan virus ke manusia lebih mudah terjadi bila orang tersebut melakukan kontak langsung dengan aktivitas peternakan.Orang yang mempunyai risiko tinggi terserang flu burung adalah pekerja peternakan unggas, penjual, penjamah unggas, sampai ke dokter hewan yang bertugas memeriksa kesehatan ternak di peternakan.</p>\r\n\r\n<p><strong>3. </strong><strong>Penularan antar manusia</strong></p>\r\n\r\n<p>Penularan flu burung antar manusia belum dapat dibuktikan, tetapi tetap perlu diwaspadai. Hal ini dikarenakan virus cepat bermutasi dan beradaptasi dengan manusia sehingga memungkinkan adanya varian baru dari virus flu burung yang dapat menular antar manusia.</p>\r\n\r\n<p><strong>Gejala:</strong></p>\r\n\r\n<p>Secara umum pada masa inkubasi, antara mulai tertular dan timbulnya gejala, adalah sekitar tiga hari.Sementar, dalam kepustakaan dinyatakan, masa infeksius pada manusia adalah satu hari sebelum sampai 3-5 hari sesudah timbul gejala. Samentara pada anak bisa sampai 24 hari.Gejala manusia yang tertular flu burung pada dasarnya sama dengan flu umumnya, hanya saja berpotensi menjadi berat dan fatal. Gejalanya antara lain demam, batuk, sakit tenggorokan, sakit kepala, dan nyeri sendi sampai infeksi selaput mata.</p>\r\n\r\n<p>Jika keadaannya makin memburuk, maka dapat terjadi severe respiratory distress yang di tandai dengan sesak nafas hebat, rendahnya kadar oksigen darah serta meningkatnya kadar CO2. Ini terjadi karena infeksi flu menyebar ke paru dan menimbulkan radang paru (pneumonia) yang dapat disebabkan oleh virus AI atau bakteri.Kemudian masuk ke saluran napas dan menginfeksi paru yang sedang sakit akibat virus flu burung.</p>\r\n\r\n<p>Laporan dari kasus yang terjadi pada tahun 1999 menunjukkan adanya variasi gejala berupa demam sekitar 390C, lemas, sakit tenggorok, sakit kepala, tidak nafsu makan, muntah dan nyeri perut, serta diare. Hanya saja, kesepuluh pasien flu burung di Vietnam tahun 2004, tidak seorang pun yang mengeluh sakit tenggorok dan pilek.Agak aneh memang.Juga tidak ada keluhan radang selaput mata dan bercak kemerahan pada pasien.</p>\r\n\r\n<p>Secara khusus, gejala flu burung dibedakan atas :</p>\r\n\r\n<p><strong>1. </strong><strong>Flu burung pada ternak</strong></p>\r\n\r\n<p>Gejala klinis flu burung pada unggas mirip dengan gejala newcastle disease, atau di indonesia disebut penyakit tetelo atau pileren yang disebabkan oleh paramyxovirus. Gejala Klinis ternak unggas yang terinfeksi flu burung sebagai berikut:</p>\r\n\r\n<ul>\r\n	<li>Jengger, pial, dan kulit perut yang tidak ditumbuhi bulu bewarna biru keunguan.</li>\r\n	<li>Pembengkakan di sekitar kepala dan muka.</li>\r\n	<li>Ada cairan yang keluar dari hidung dan mata.</li>\r\n	<li>Perdarahan di bawah kulit (subkutan)</li>\r\n	<li>Perdarahan titik (ptechie) pada daerah dada, kaki, dan telapak kaki.</li>\r\n	<li>Batuk, bersin, ngorok.</li>\r\n	<li>Diare.</li>\r\n	<li>Tingkat kematian tinggi.</li>\r\n</ul>\r\n\r\n<p><strong>2. </strong><strong>Flu burung pada manusia</strong></p>\r\n\r\n<p>Orang yang terserang flu burung menunjukkan gejala seperti terkena flu biasa, tetapi kerena keganasan virusnya menyebabkan flu ini juga ganas. Virus influenza biasanya menimbulkan penyakit yang ringan.Tetapi virus flu burung ini sangat ganas dan dapat menyebabkan kematian dalam satu minggu.Orang yang terkena flu burung mengalami kenaikan suhu tubuh sampai 39C, sakit tenggorokan, batuk, sesak napas dan mengeluarkan lendir bening dari hidung.Kondisi ini dapat diikuti dengan penurunan daya tahan tubuh yang sangat cepat karena biasanya penderita tidak memiliki nafsu makan, diare dan muntah.</p>\r\n\r\n<p>Dalam waktu singkat gejala gejala tersebut dapat menjadi lebih berat dengan terjadinya peradangan di paru (pneumonia).Apabila tidak dilakukan penanganan yang baik pada pasien maka dapat menyebabkan kematian.</p>\r\n\r\n<p>&nbsp;</p>\r\n', '<p><strong>Pencegahan:</strong></p>\r\n\r\n<p>Kebiasaan pola hidup sehat tetap memegang peranan penting dalam pencegahan.Untuk flu adalah tetap menjaga daya tahan tubuh, makan yang seimbang dan bergizi, istirahat dan olahraga teratur.Kebiasaan mencuci tangan secara teratur.Secara umum pasien influenza sebaiknya istirahat, banyak minum dan makan bergizi.Sampai kini belum ada vaksin untuk menangkal flu burung pada manusia walau ada berbagai jenis vaksin influenza, tetapi vaksin tersebut dibuat untuk mencegah flu biasa bukan mencegah flu burung.</p>\r\n\r\n<p>World Health Organization (WHO) menyatakan, secara umum prinsip-prinsip kerja yang higienis seperti mencuci tangan dan menggunakan alat pelindung diri bila diperlukan merupakan upaya yang harus dilakukan oleh mereka yang kontak dengan ternak.Karena telur juga dapat tertular, penanganannya kulit telur dan telur mentah juga perlu diperhatikan. WHO juga menyatakan, dengan memasaknya seperti yang biasa kita lakukan selama ini, virus flu burung akan mati. Ada anjuran: daging, daging unggas harus dimasak sampai suhu 700C atau 800C selama sedikitnya satu menit. Kalau kita menggoreng atau merebus ayam di dapur misalnya, tuntu lebih dari itu suhu dan lamanya memasak.Artinya aman mengkonsumsi ayam atau unggas lainnya asal telah dimasak dengan baik.</p>\r\n\r\n<p>Flu burung yang mana belum ada obat atau vaksinnya, maka upaya yang dilakukan hanya bersifat pencegahan dan pertolongan pertama. Upaya tersebut dapat dilakukan dengan pencegahan luar dan dalam tubuh.</p>\r\n\r\n<p><strong>1. Pencegahan Luar</strong></p>\r\n\r\n<p>Pencegahan luar bertujuan untuk mencegah penularan dari lingkungan agar tidak masuk ke dalam tubuh. Tindakannya adalah:</p>\r\n\r\n<ul>\r\n	<li>Setiap orang yang berhubungan dengan bahan yang berasal dari unggas harus menggunakan pelindung.</li>\r\n	<li>Memusnahkan unggas yang terkena flu burung.</li>\r\n	<li>Peternakan harus dijauhkan dari perumahan untuk mengurangi resiko penularan.</li>\r\n	<li>Tidak mengkonsumsi produk unggas dari peternakan yang terkena wabah flu burung.</li>\r\n	<li>Tetap terapkan pola hidup sehat.</li>\r\n</ul>\r\n\r\n<p><strong>2. Pencegahan Dalam</strong></p>\r\n\r\n<p>Pencegahan dalam dilakukan dengan mengonsumsi obat dan makanan untuk meningkatkan daya tahan tubuh.</p>\r\n\r\n<ul>\r\n	<li>Obat</li>\r\n</ul>\r\n\r\n<p>Obat yang direkomendasikan untuk mencegah terinfeksi flu burung adalah obat antiviral misalnya amantadine dan rimantadine dan penghambat neurominidase misalnya oseltamivir dan zanimivir. Obat ini digunakan dalam pencegahan dan pengobatan influenza di beberapa Negara dan diperkirakan dapat juga mengatasi penyakit flu burung.</p>\r\n\r\n<ul>\r\n	<li>Makanan</li>\r\n</ul>\r\n\r\n<p>Mengkonsumsi makanan yang banayak mengandung serat dan kandungan antioksidan tinggi seperti buah dan sayuran. Dengan melaksanakan upaya pencegahan diatas diharapkan kita semua dapat terhindar dari penyakit flu burung ini.</p>\r\n\r\n<p><strong>Pengobatan:</strong></p>\r\n\r\n<p><strong>1. </strong><strong>Pengobatan flu burung pada ternak</strong></p>\r\n\r\n<p>Virus flu burung yang dapat menyerang pada hewan saat ini belum diketahui obat maupun vaksin yang tepat untuk mengobatinya.Pemberian obat maupun vaksin dilakukan lebih ke arah pencegahan supaya tidak menular kepada hewan lain maupun manusia di sekitarnya. Beberapa langkah yang dapat ditempuh dalam penanggulangan pengobatan flu burung antara lain sebagai berikut:</p>\r\n\r\n<p><strong>Biosekuriti</strong></p>\r\n\r\n<p>Disebut juga keamanan hayati, yaitu perlakuan yang ditujukan untuk menjaga keamanan hayati demi pemeliharaan kesehatan dan memperkecil ancaman terhadap individu yang dilindungi. Usaha ini antara lain:</p>\r\n\r\n<ul>\r\n	<li>Membatasi secara ketat lalu lintas unggas atau ternak, produk unggas, pakan, kotoran, bulu, dan alas kandang.</li>\r\n	<li>Membatasi lalu lintas pekerja atau orang dan kendaraan keluar masuk peternakan.</li>\r\n	<li>Peternak dan orang yang hendak masuk peternakan harus memakai pakaian pelindung seperti masker, kaca mata plastik, kaos tangan, dan sepatu.</li>\r\n	<li>Mencegah kontak antara unggas dengan burung liar.</li>\r\n</ul>\r\n\r\n<p><strong>Depopulasi</strong></p>\r\n\r\n<p>Depopulasi adalah tindakan pemusnahan unggas secara selektif di peternakan yang tertular virus flu burung. Tindakan ini dilakukan untuk mencegah penyebaran penyakit lebih luas. Cara pemusnahan unggas yang terinfeksi virus flu burung adalah menyembelih semua unggas yang sakit dan yang sehat dalam satu kandang (peternakan). Selain itu, dapat juga dilakukan dengan cara disposal, yaitu membakar dan mengubur unggas mati, sekam dan pakan yang tercemar, serta bahan dan peralatan yang terkontaminasi.</p>\r\n\r\n<p>Dilakukan pada semua jenis unggas yang sehat di daerah yang telah diketahui ada virus flu burung. Vaksin yang digunakan adalah vaksin inaktif (killed vaccine) yang resmi dari pemerintah.</p>\r\n\r\n<p><strong>2. </strong><strong>Pengobatan flu burung pada manusia</strong></p>\r\n\r\n<p>Flu burung pada manusia belum ada obatnya. Meskipun tidak semua penderita mengalami kematian, flu burung tetap harus diwaspadai karena dikhawatirkan virus ini akan mengalami mutasi menjadi lebih ganas. Berikut ini beberapa tindakan untuk mewaspadai flu burung:</p>\r\n\r\n<ul>\r\n	<li>Berolahraga secara teratur, sehingga fisik sehat.</li>\r\n	<li>Makan makanan yang bergizi, agar dapat menyuplai energi untuk pembentukan kekebalan tubuh yang optimal.</li>\r\n	<li>Mengkonsumsi produk unggas yang benar-benar sudah matang.</li>\r\n	<li>Hindari berkunjung ke peternakan.</li>\r\n	<li>Seringlah mencuci tangan dan hindari meletakkan tangan di hidung dan mulut.</li>\r\n	<li>Membiasakan hidup bersih dan menjaga kebersihan lingkungan.</li>\r\n	<li>Cukup istirahat.</li>\r\n</ul>\r\n\r\n<p>Jika ada yang terkena flu burung di sekitar kita maka langkah yang dapat diambil adalah:</p>\r\n\r\n<ul>\r\n	<li>Tidak panik, tapi tetap waspada.</li>\r\n	<li>Membawa penderita ke dokter atau rumah sakit terdekat.</li>\r\n	<li>Melaporkan pada pihak terkait, seperti Dinas Peternakan atau Dinas Kesehatan setempat supaya ditindaklanjuti.</li>\r\n	<li>Tidak mengucilkan keluarga penderita karena keluarga penderita belum tentu tertular.Selain itu belum ada bukti bahwa flu burung menular antar manusia.</li>\r\n	<li>Penanggulangan di rumah sakit :</li>\r\n	<li>Penderita dirawat di ruang isolasi selama 7 hari (masa penularan).</li>\r\n	<li>Oksigenasi, dengan mempertahankan saturasi O2 &gt; 90 %</li>\r\n	<li>Hidrasi/ Jaga ion dan mineral tubuh tercukupi</li>\r\n	<li>Antibiotika, anti inflamasi , obat &ndash;obatan imunomodulator</li>\r\n	<li>Terapi simptomatis untuk gejala flu, seperti analgetika atau antipiretika, mukolitik, dekongestan.</li>\r\n</ul>\r\n', '03 Flu Burung.jpg'),
(17, 'Tetelo (Newcastle Disease)', '<p>Newcastle Disease (ND) adalah penyakit yang sangat menular, dengan angka kematian yang <em>tinggi, disebabkan oleh virus genus paramyxovirus dengan famili </em>&nbsp;<em>paramyxoviridae</em>. Nama lain untuk ND adalah tetelo<em>, pseudovogolpest</em>, sampar ayam, <em>Rhaniket, Pneumoencephalitis </em>dan <em>Tontaor furrens. </em>Newcastle Disease dipandang sebagai salah satu penyakit penting di bidang perunggasan. Kejadian wabah penyakit ND seringkali terjadi pada kelompok ayam yang tidak memiliki kekebalan atau pada kelompok yang memiliki kekebalan rendah akibat terlambat divaksinasi atau karena kegagalan program vaksinasi. Kerugian yang ditimbulkan oleh penyakit ND antara lain berupa kematian ayam, penurunan produksi telur pada ayam petelur, gangguan pertumbuhan dan penurunan berat badan pada ayam pedaging. Penyakit tetelo disebabkan oleh virus yang berukuran 100-250 nm, yang tersusun dari Asam Inti Ribonukleat (ARN) atau sering disebut Ribonucleic Acid (RNA), protein dan lemak. Virus ini termasuk dalam Famili Paramyxoviridae dengan genera Genus Pneumovirus atau Genus Paramyxovirus (PMV). &nbsp;Penyakit ND (tetelo) menyerang unggas dan burung. Ayam ras, ayam kampung baik piaraan maupun yang liar sangat rentan, yang muda lebih rentan daripada yang dewasa dan mengakibatkan mortalitas (kematian) tinggi, sedangkan jenis kelamin tidak mempengaruhi kerentanan ini (Balai Penyuluhan Pertanian, 2010).</p>\r\n\r\n<p><strong>Penularan:</strong></p>\r\n\r\n<p>Penularan penyakit ND (tetelo) dari satu hewan ke hewan lainnya melalui kontak, dengan hewan sakit,&nbsp;<em>skeresi, ekskresi</em>&nbsp;dari hewan sakit serta juga bangkai penderita ND. Jalan penularan melalui alat pencernaan dan pernafasan, virus yang tercampur lendir atau virus yang ada dalam feses dan urine tahan dua bulan bahkan dalam keadaan kering tahan lebih lama lagi. Demikian pula virus yang mencemari litter dan perlengkapan kandang. Hal ini merupakan sumber penularan yang penting (Balai Penyuluhan Pertanian, 2010).</p>\r\n\r\n<p><strong>Gejala Klinis:</strong></p>\r\n\r\n<p><strong><a href=\"http://localhost/spkayam/gambar/posting/tetelo.jpeg\"><img alt=\"\" src=\"http://localhost/spkayam/gambar/posting/tetelo.jpeg\" style=\"height:319px; width:348px\" /></a></strong></p>\r\n\r\n<p>Gejala penyakit ini dapat diamati melalui gejala pernafasan seperti bersin-bersin, batuk, sukar bernafas, megap-megap dan ngorok; gejala syaraf berupa sayap terkulai, kaki lumpuh (jalan terseret), jalan mundur (sempoyongan) serta kepala dan leher terpuntir (torticoles) yang merupakan gejala khas penyakit ini. Kemudian gejala pencernaan meliputi diare berwarna hijau, jaringan sekitar mata dan leher bengkak, pada ayam petelur produksinya berhenti, kalau sudah sembuh kualitas telurnya jelek, warna abnormal, bentuk dan permukaannya abnormal dan putih telurnya encer. Hal ini disebabkan oleh karena organ reproduksinya tidak dapat normal kembali. Umumnya kematian anak ayam dan ayam muda lebih tinggi dibandingkan ayam tua.</p>\r\n\r\n<p><strong>Diagnosis:</strong></p>\r\n\r\n<p>Untuk mengetahui unggas yang terinfeksi ND adalah dengan melacak keberadaan antibodi pada serumnya. Metode yang dipergunakan adalah metode Enzym Linked Immunosorbent Assay (ELISA) dan Western Imunoblotting. Caranya sampel darah diambil dari unggas yang tidak pernah divaksinasi dengan vaksin ND. Sehingga, adanya antibodi ND pada sampel yang diperiksa menandakan bahwa unggas itu pernah terinfeksi virus ND bukan akibat vaksinasi. Darah diambil dari vena brachialis (vena di bagian sayap),menggunakan dispossible syringe 2,5 CC yang digunakan sekali pakai. Darah ditampung dalam sebuah tabung reaksi, didiamkan semalam pada lemari pendingin, kemudian serum dipisahkan dengan cara di centrifuge.</p>\r\n', '<p><strong>Pencegahan:</strong></p>\r\n\r\n<p>Tindakan vaksinasi merupakan langkah yang tepat sebagai upaya pencegahan terhadap penyakit ND. Program vaksinasi yang secara umum diterapkan, yaitu</p>\r\n\r\n<ol>\r\n	<li>Pada infeksi lentogenik ayam pedaging, dicegah dengan pemberian vaksin aerosol atau tetes mata pada anak ayam umur sehari dengan menggunakan vaksin Hitchner B1 dan dilanjutkan dengan booster melalui air minum atau secara aerosol.</li>\r\n	<li>Pada infeksi lentogenik ayam pembibit dapat dicegah dengan pemberian vaksin Hitchner B1 secara aerosol atau tetes mata pada hari ke-10. Vaksinasi berikutnya dilakukan pada umur 24 hari dan 8 minggu dengan vaksin Hitchner B1 atau vaksin LaSota dalam air, diikuti dengan pemberian vaksin emulsi multivalen yang diinaktivasi dengan minyak pada umur 18 &ndash; 20 minggu. Vaksin multivalen ini dapat diberikan lagi pada umur 45 minggu, tergantung kepada titer antibodi kawanan ayam, resiko terjangkitnya penyakit dan faktorfaktor lain yang berhubungan dengan pemeliharaan.</li>\r\n</ol>\r\n\r\n<p>Tindakan pencegahan selain vaksinasi adalah sanitasi. Hal-hal yang perlu diperhatikan, antara lain :</p>\r\n\r\n<ol>\r\n	<li>Sebelum kandang dipakai, kandang dibersihkan kemudian dilabur dengan kapur yang dibubuhi NaOH 2%. Desinfeksi kandang dilakukan secara fumigasi dengan menggunakan fumigant berupa formalin 1 &ndash; 2% dan KMnO4, dengan perbandingan 1 : 5000.</li>\r\n	<li>Liter diupayakan tetap kering, bersih dengan ventilasi yang baik. Bebaskan kandang dari hewan-hewan vektor yang bisa memindahkan virus ND. Kandang diusahakan mendapat cukup sinar matahari.</li>\r\n	<li>Hindari penggunaan karung bekas (4) DOC harus berasal dari perusahaan pembibit yang bebas dari ND (5) di pintupintu masuk disediakan tempat penghapus hamaan, baik untuk alat transportasi maupun orang. (6) memberikan pakan yang cukup kuantitas maupun kualitas.</li>\r\n</ol>\r\n\r\n<p><strong>Pengendalian:</strong></p>\r\n\r\n<p>Tindakan pengendalian untuk menekan penularan penyakit ND sangat diperlukan. Tindakan-tindakan tersebut, antara lain meliputi:</p>\r\n\r\n<ol>\r\n	<li>Unggas yang mati karena ND harus dibakar atau dikubur.</li>\r\n	<li>Larangan mengeluarkan unggas, baik dalam keadaan mati atau hidup bagi peternakan yang terkena wabah ND, kecuali untuk kepentingan diagnosis.</li>\r\n	<li>Larangan menetaskan telur dari unggas penderita ND dan izin menetaskan telur harus dicabut selama masih ada wabah ND pada perusahaan pembibit.</li>\r\n</ol>\r\n', '04 Tetelo.png'),
(18, 'Tipus Ayam (Fowl Typhoid)', '<p>Penyakit tipus pada ayam atau <em>Fowl typhoid</em> disebabkan oleh bakteri Salmonella gallinarum yang ditularkan lewat sisa makanan dan ceceran air minum yang membusuk. Penyakit ini ditularkan pula melalui lalat, tikus, kecoa, ayam tetangga, udara yang berputar di dalam kandang atau peralatan kandang yang tak dibersihkan. Penyakit ini pertama kali tercatat pada abad ke-18. Namun baru pada tahun 1880-an, Louis Pasteur pertama kali mengisolasi dan menanamnya dalam budaya murni. Awalnya penyakit unggas di Eropa, pertama kali tercatat di Amerika Utara pada tahun 1943-44. Sejak itu wabah telah tercatat hampir setiap tahun pada burung liar. Saat ini, penyakit ini paling banyak terjadi di unggas liar Amerika Utara.<br />\r\nPada tahun 2011 wabah flu burung membunuh ribuan bebek baik di wilayah Arktik Kanada. Para ilmuwan sedang mempelajari wabah dan potensinya untuk menyebar ke Greenland. Pada bulan Maret 2015, wabah lain dari unggas kolera membunuh sekitar 2.000 angsa salju di Idaho utara saat menerbangkan migrasi musim semi ke Kanada.</p>\r\n\r\n<p><strong>Epidemiologi:</strong></p>\r\n\r\n<p>Wabah terjadi pada cuaca dingin dan basah (di akhir musim panas, musim gugur dan musim dingin). Wabah ini sering ditelusuri kembali ke keberadaan hewan pengerat di rumah pengembangbiakan. Ini diperkirakan menyebarkan penyakit dari bangkai burung mati (mungkin dari halaman belakang tetangga), dibuang dengan tidak semestinya. Begitu penyakit ini diperkenalkan pada kawanan domba, penyakit itu akan tetap tinggal sampai pemusnahan. Pengangkut kronis selalu dapat menyebabkan munculnya kembali penyakit pada unggas yang rentan.<br />\r\nPada burung liar, penyakit ini paling sering dikaitkan dengan lahan basah. Blanchong dkk. menentukan bahwa lahan basah bertindak sebagai reservoir jangka pendek, mencatat sejumlah besar bakteri di dalam tanah dan air selama wabah. Lahan basah, bagaimanapun, bukan waduk jangka panjang.<br />\r\nPenyakit ini muncul dalam dua bentuk yang sangat berbeda: akut dan kronis. Burung dengan kolera unggas kronis, yang lebih umum di unggas rumahan, menunjukkan adanya penyakit berkepanjangan dengan infeksi yang lebih terlokalisir. Infeksi kronis telah ditunjukkan pada angsa salju, dan orang-orang ini diyakini merupakan wortel migran jangka panjang untuk penyakit ini.<br />\r\nBegitu bakteri dimasukkan ke dalam populasi burung yang rentan, wabah akut kolera unggas mengikuti. Burung yang terinfeksi akan mati 6-12 jam setelah tertular bakteri, dan sangat sedikit unggas yang sakit telah dijelaskan. Karena asosiasi dan agregasi padat, unggas air paling sering terkena P. multocida, betapapun pemulung dan burung air lainnya sering terkena wabah multi spesies.</p>\r\n\r\n<p><strong>Gejala:</strong></p>\r\n\r\n<ul>\r\n	<li>Bulu pada daerah kloaka basah oleh kotoran yang melekat.</li>\r\n	<li>Mencret Kehijauan</li>\r\n	<li>Kotoran encer dan berwarna kuning.</li>\r\n	<li>Suhu badan panas sekali.</li>\r\n	<li>Bernafas dengan cepat sekali.</li>\r\n	<li>Kelihatan haus terus.</li>\r\n	<li>Tidak mau makan atau nafsu makan pada ayam tidak ada.</li>\r\n</ul>\r\n\r\n<p><strong>Tanda Kilnis dan Mortem</strong></p>\r\n\r\n<p>Pada kasus akut, diare hijau bisa menjadi gejala awal. Gejala yang paling khas, dalam kasus kronis, adalah pembengkakan pada kelambir.&nbsp; Hal ini lebih sering terjadi pada jenis lokal. Alih-alih infeksi umum, infeksi lokal lebih khas. Hal ini sering terjadi pada saluran pernapasan termasuk sinus dan tulang pneumato, persendian hock, bursa sternal, alas kaki, rongga peritoneal dan saluran telur.</p>\r\n\r\n<p><a href=\"http://localhost/spkayam/gambar/posting/tipus ayam.jpg\"><img alt=\"\" src=\"http://localhost/spkayam/gambar/posting/tipus ayam.jpg\" style=\"height:163px; width:220px\" /></a><br />\r\nDalam kasus akut, yang paling khas p.m. Lesi adalah petechiae yang diamati pada jaringan lemak epikardial. Fokus nekrotik pada hati biasanya ditemukan dan hiperemia umum biasa terjadi. Karena kecepatan infeksi dan kematian, burung berada dalam kondisi tubuh yang baik dan tidak menunjukkan tanda-tanda penyakit berkepanjangan.</p>\r\n', '<p><strong>Pencegahan:</strong></p>\r\n\r\n<ul>\r\n	<li>Ayam yang masih kelihatan sehat segera dipindah ke kandang baru, bersih dan telah disemprot dengan cetamium.</li>\r\n	<li>Diberi vaksinasi secara periodik.</li>\r\n	<li>Sinar matahari diusahakan dapat masuk ke dalam kandang minimal pada pagi hari.</li>\r\n	<li>Kandang lama bila mempergunakan lantai litter atau pasir diganti baru yang bersih, kering dan bebas debu dan kemudian disemprot dengan jodophor.</li>\r\n	<li>Pada air minum diberi campuran coxalin.</li>\r\n	<li>Ayam yang sudah terserang penyakit cepat-cepat disingkirkan ke kandang isolasi untuk mendapatkan perawatan intensif.</li>\r\n</ul>\r\n\r\n<p><strong>Pengobatan:</strong></p>\r\n\r\n<p>Dengan tetra chlor, furox, neo sulfa, furol tetra, nocci, furazon 10, ebs 3, neo terramycin atau suntikan terramycin menurut aturan sesuai pada kemasannya.</p>\r\n', '05 Tipus Ayam.jpg');
INSERT INTO `post` (`kode_post`, `nama_post`, `det_post`, `srn_post`, `gambar`) VALUES
(19, 'Berak Darah (Coccidosis)', '<p>Avian Coccidiosis (koksidiosis) merupakan penyakit usus yang disebabkan oleh protozoa parasit Genus Eimeria (Allen dan Fetterer, 2002). Eimeria berkembang biak di saluran pencernaan dan menyebabkan kerusakan jaringan (Calnek dkk., 2001). Koksidiosis pada ayam berlokasi pada dua tempat yaitu di sekum (caecal coccidiosis) yang disebabkan oleh E. tenella dan di usus (intestinal coccidiosis) yang disebabkan oleh delapan jenis lainnya (Jordan dkk., 2001). Koksidiosis merupakan salah satu penyakit yang banyak mendatangkan masalah dan kerugian pada peternakan ayam. Kerugian yang ditimbulkan meliputi kematian (mortalitas), penurunan berat badan, pertumbuhan terhambat, nafsu makan menurun, produksi daging turun, meningkatnya biaya pengobatan, upah tenaga kerja dan lain-lain. Kerugian yang ditimbulkan dapat menghambat perkembangan peternakan ayam dan menurunkan produksi protein hewani, oleh karena itu pengendalian koksidiosis pada ayam perlu mendapat perhatian (Tabbu, 2006). .&nbsp;</p>\r\n\r\n<p><strong>Gejala Klinis:</strong></p>\r\n\r\n<p><strong><a href=\"http://localhost/spkayam/gambar/posting/06Berak Darah.jpeg\"><img alt=\"\" src=\"http://localhost/spkayam/gambar/posting/06Berak Darah.jpeg\" style=\"height:259px; width:485px\" /></a></strong></p>\r\n\r\n<p>Spesies yang berbeda akan memberikan gejala klinis yang berbeda pula, gejala klinis yang ditimbulkan bervariasi pada infeksi bermacam spesies dan juga pada banyak sedikitnya jumlah koksidia yang menginfeksi dan resistensi hospes. Spesies yang kurang pathogen tidak atau sedikit menunjukan gejala klinis. Gejala klinis dari penyakit ini yang disebabkan parasit Eimeria tenella adalah :</p>\r\n\r\n<ol>\r\n	<li>Ekskreta berdarah dan mencret.</li>\r\n	<li>Nafsu makan kurang.</li>\r\n	<li>Sayap terkulasi.</li>\r\n	<li>Bulu kusam.</li>\r\n	<li>Menggigil kedinginan.</li>\r\n</ol>\r\n\r\n<p><strong>Penyebab:</strong></p>\r\n\r\n<p>Koksidiosis merupakan penyakit yang disebabkan oleh protozoa yang bernama Eimeria sp famili Eimeriidae atau yang lebih sering dikenal dengan penyakit berak darah, dimana Eimeria ini mengivestasi bibit mikroorganisme kedalam sel tubuh sehingga melahirkan gangguan kesehatan infestasi klinis yang merusakkan jaringan pencernaan terutama usus. Akibatnya terjadi pada proses pencernaan berupa gangguan metabolisme dan penyerapan zat makanan, bahkan kehilangan darah dari rusaknya jaringan usus, dan hampir pasti rentan terhadap penyakit lain.</p>\r\n\r\n<p><strong>Diagnosa:</strong></p>\r\n\r\n<p>Diagnosa sangkaan terhadap koksidiosis dapat di dasarkan atas gejala klinik, perubahan patologik yang berhubungan dengan lokasi sejumlah besar ookista atau stadium aseksual Eimeria (sporozoit, merozoit, skison) dan riwayat kasus Tabbu, (2006). Diagnosa laboratorium dapat dilakukan dengan melakukan uji natif, uji apung dan uji sentrifus terhadap feses yang diduga terinfeksi Eimeria, Sp.</p>\r\n\r\n<p><strong>Umur yang di serang:</strong></p>\r\n\r\n<p>Koksidiosis pada sekum oleh Eimeria tenella paling sering terjadi pada ayam muda berumur 4 minggu, karena umur tersebut adalah umur yang paling peka. Ayam yang berumur 1-2 minggu lebih resisten, walaupun demikian Eimeria tenella &nbsp;dapat juga menginfeksi ayam yang sudah tua. Ayam yang sudah tua umumnya memiliki kekebalan imunitas akibat sudah terinfeksi sebelumnya. Pada umumnya koksidiosis sekum terjadi akibat infeksi berat dalam waktu yang relative pendek tidak lebih dari 72 jam. Pada ayam umur 1-2 minggu diperlukan 200.000 ookista untuk menyebabkan kematian, dan diperlukan 50.000-100.000 ookista untuk menyebabkan kematian pada ayam yang berumur lebih tua. Pada kelompok ayam, mula-mula gejala terlihat 72 jam setelah infeksi. Ayam terkulai, anoreksia, berkelompok agar badannya hangat dan hari keempat sesudah infeksi terdapat darah di dalam tinja. Darah paling banyak ditemukan pada hari kelima dan keenam sesudah infeksi dan menjelang hari kedelapan atau kesembilan ayam sudah mati atau dalam tahap persembuhan. Kematian paling tinggi terjadi antara hari keempat dan keenam karena kehilangan banyak darah. Kematian kadang-kadang terjadi tanpa diduga. Jika ayam sembuh dari penyakit akut maka penyakit akan bersifat kronis.</p>\r\n\r\n<p><strong>Penularan:</strong></p>\r\n\r\n<p>Penyakit ini dapat ditularkan secara mekanik malalui pekerja kandang, peralatan yang tercemar atau dalam beberapa kasus yang pernah terjadi dapat disebarkan melalui debu kandang dan litter dalam jangkauan pendek. Berat tidaknya penyakit ini tergantung dari jumlah protozoa yang termakan.</p>\r\n\r\n<p><strong>Kerugian:</strong></p>\r\n\r\n<p>Kemungkinan kerugian yang ditimbulkan dari penyakit ini jelas terjadi berupa kemerosotan produksi yang cukup signifikan, serta menjadi pemicu gagalnya program vaksinasi, dengan titer antibody yang diperoleh akan rendah dan tidak optimal dapat memicu timbulnya penyakit lain seperti ND, Gumboro, Mareks bahkan Coryza atau biasa yang disebut infeksi sekunder.</p>\r\n', '<p><strong>Pengobatan:</strong></p>\r\n\r\n<p>Untuk pengobatannya dapat dilakukan dengan cara pemberian larutan amprolium atau sulfonamide dalam air minum dan pemberian air yang dapat mensuspensi suplemen vitamin A dan K dapat mempercepat proses penyembuhan.</p>\r\n\r\n<p><strong>Pencegahan:</strong></p>\r\n\r\n<p>Untuk pencegahan dapat dilakukan dengan cara sebagai berikut :</p>\r\n\r\n<ol>\r\n	<li>Sanitasi dan ventilasi kandang harus baik.</li>\r\n	<li>Pengangkatan litter setiap kali panen pada broiler.</li>\r\n	<li>Lantai kandang dicuci pakai air untuk membersihkan kotoran, pencucian tahap kedua dengan deterjen.</li>\r\n	<li>Menaburkan bubuk kapur di dalam kandang.</li>\r\n	<li>Peralatan feeder dan drinker dicuci sebersih mungkin.</li>\r\n	<li>Kandang difumigasi dengan formalin 10%.</li>\r\n	<li>Melakukan istirahat kandang 7-21 hari.</li>\r\n</ol>\r\n\r\n<p><strong>Pengendalian:</strong></p>\r\n\r\n<p>Pengendalian koksidiosis pada ayam di Indonesia umumnya dilakukan dengan pemeliharaan kebersihan, pemberian koksidiostat yang dicampurkan dalam makanan atau air minumnya, dan penggunaan vaksin koksidia. Pengendalian koksidiosis dengan pemberian koksidiostat harus diikuti cara dan takaran yang telah ditentukan agar tidak menimbulkan efek samping, bahwa pemakaian satu macam koksidiostat yang terus menerus dalam pakan ayam dapat menimbulkan galur coccidia yang tahan terhadap kokidiostat tersebut (Tabbu, 2006). Antikoksidia&nbsp; dapat menimbulkan resistensi terhadap koksidiosis. Industri farmasi ada usaha untuk mengatasi masalah resistensi koksidiosis pada unggas (Allen dan Fetterer, 2002).</p>\r\n', '06 Berak Darah.jpg'),
(20, 'Gumboro (Infectious Bursal Disease)', '<p>Penyakit Gumboro atau Penyakit Infectious Bursal Disease<em> </em>(IBD) merupakan penyakit pada ayam yang pertama kali dilaporkan oleh Cosgrove pada tahun 1962 berdasarkan kasus yang terjadi pada tahun 1957 di desa Gumboro-Delaware, negara bagian Amerika Serikat. Sesuai dengan nama asal daerah ditemukannya, penyakit ini dikenal juga sebagai Gumboro. Penyebab penyakit gumboro (IBD) adalah virus yang berbentuk <em>icosahedral </em>yang terdiri dari 2 segmen untaian ganda RNA, yang termasuk dalam famili <em>Birnaviridae </em>(Lukert dan Saif, 2003) Virus <em>very virulent </em>IBD (vvIBDv) bersifat sangat menular dan akut, menyebabkan angka morbiditas dan mortalitas yang tinggi. Penyakit ini berdampak ekonomis karena menyerang organ pertahanan ayam yaitu bursa <em>Fabricius </em>sehingga merugikan peternak. Ayam yang terserang gumboro (IBD) menjadi rentan terhadap infeksi sekunder, serta mengakibatkan kegagalan vaksinasi (Lukert dan Saif, 2003).</p>\r\n\r\n<p><strong>NAMA LAIN</strong></p>\r\n\r\n<p>Nama lain: Infectious Bursal Disease (IBD), Avian nephrosis atau Avian Infectious Bursitis. Merupakan penyakit menular akut pada ayam berumur muda yang ditandai dengan peradangan berat bursa fabrisius dan bersifat immunosupresif yaitu lumpuhnya system pertahanan tubuh ayam yang mengakibatkan turunnya respon ayam terhadap vaksinasi dan ayam-ayam menjadi lebih peka terhadap pathogen lainnya.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>ETIOLOGI</strong></p>\r\n\r\n<p>Virus penyebab Gumboro (IBD) yang dikenal saat ini terdiri dari 2 serotipe yaitu serotipe 1 dan serotipe 2 yang dapat menginfeksi ayam dan kalkun. Serotipe 1 yang pertama kali ditemukan disebut dengan <em>strain </em>klasik yang bersifat patogen dan <em>strain </em>yang ditemukan kemudian di daerah Amerika merupakan <em>strain </em>varian yang sangat ganas yaitu <em>very virulent </em>IBD (vvIBD). Virus IBD tersebut merupakan hasil mutasi dari virus klasik, sementara serotipe 2 tidak bersifat ganas. Kedua serotipe dapat dibedakan dengan uji virus netralisasi (VN) tetapi tidak dapat dibedakan dengan <em>Flourescent</em> <em>Antibody Technique </em>(FAT) dan <em>Enzyme Linked</em> <em>Immunosorbent Assay </em>(Elisa) (Lukert dan Saif, 2003). Virus IBD berdiameter 55 nm, merupakan virus yang tidak memiliki amplop dan dikelilingi oleh protein <em>capsid </em>yang berbentuk ikosahedral (Hirai dan Shimakura, 1974). Virus ini tergolong dalam famili <em>Birnaviridae</em>. Sesuai dengan namanya, virus terdiri dari 2 segmen utas ganda RNA, yaitu segmen A mempunyai ukuran 3300 pasang basa, yang terdiri dari 2 bagian <em>Open Reading Frame</em>, yaitu A1 dan A2.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>PATOGENESIS</strong></p>\r\n\r\n<p>Patogenesis adalah jalannya virus sehingga menimbulkan lesi, yang dapat menyebabkan kematian, penyakit atau efek imunosupresif pada ayam. Penyakit Gumboro (IBD) menyerang ayam umur 3 &ndash; 6 minggu pada saat perkembangan bursa <em>Fabricius </em>mencapai optimum. Pada saat yang sama antibodi asal induk mulai menurun, sehingga ayam rentan terhadap infeksi virus IBD. Sebaliknya, penyakit Gumboro (IBD) tidak membahayakan bagi ayam yang telah mengalami regresi bursa <em>Fabricius, </em>karena target sel virus IBD adalah sel limfoid bursa <em>Fabricius </em>yang sudah matang. Infeksi IBD menyebabkan kerusakan pada bursa <em>Fabricius</em> yang berupa nekrosis dan apoptosis pada sel limosit B Infeksi pada umumnya melalui oral bersama pakan yang tercerna virus masuk ke dalam usus. Virus kemudian ditangkap oleh sel makrofag atau limfosit sebagai <em>Antigen Precenting Cell </em>(APC). Keberadaan IBD dapat dideteksi 13 jam paska infeksi pada sebagian besar folikel (Van Den Berg, 2000).</p>\r\n\r\n<p>Penyebab kematian belum diketahui secara pasti. Namun demikian pada fase akut teramati sindroma <em>septic shock</em>, dimana terjadi respon imun yang berlebihan, yang ditandai dengan peningkatan konsentrasi TNF-&alpha; yang berlebihan di dalam serum darah ayam, yang kemudian diikuti terjadinya kematian (Sharma <em>et al. dalam </em>Asraf, 2005).</p>\r\n\r\n<p>Infeksi virus IBD yang ganas menyebabkan kerusakan yang parah hingga terjadi deplesi sel limfoid pada folikel bursa <em>Fabricius</em>, sehingga ukuran bursa terlihat mengecil, hingga mencapai 1/4 &ndash; 1/5 dari ukuran bursa <em>Fabricius </em>pada ayam kontrol. Bila tidak terjadi penyembuhan pada bursa <em>Fabricius </em>ayam, akan menyebabkan hambatan produksi antibodi yang dibentuk oleh sel B. Selain itu pada infeksi IBD banyak sel makrofag dan sel heterofil yang mengalami nekrosis dan apoptosis menyebabkan fungsi fagositosis yang menurun (Lam, 1998). Kedua kondisi tersebut menyebabkan ayam yang terinfeksi IBD menjadi imunosupresif.</p>\r\n\r\n<p><strong>GEJALA KLINIS</strong></p>\r\n\r\n<p>Gejala klinis yang terlihat sangat tergantung dari <em>strain </em>virus yang menginfeksi ayam, jumlah virus, umur, galur ayam, rute inokulasi dan keberadaan antibodi penetralisasi (Muller <em>et al.</em>, 2003). Virus yang masuk ke dalam tubuh ayam ditangkap makrofag, yang kemudian melepaskan sitokin yang menimbulkan respon inflamasi.</p>\r\n\r\n<p>Gejala klinis ditimbulkan oleh infeksi IBD adalah ayam lesu, nafsu makan menghilang dan sayap menggantung (Park <em>et al</em>., 2009; Acribasi <em>et al</em>., 2010). Selain itu juga sering ditemukan gejala diare, serta kotoran yang menempel pada kloaka (Parede <em>et al</em>., 2003). Pada ayam muda tanpa antibodi maternal, gejala klinis mulai terlihat pada 48 jam pi dan gejala klinis semakin parah pada 56 &ndash; 72 jam paska infeksi (William dan Davison, 2005). Sementara itu, pada ayam yang divaksinasi, gejala klinis terlihat 3 hari pasca tantang, dan ayam-ayam tersebut mati setelah 2 &ndash; 3 hari memperlihatkan gejala klinis (Park <em>et al</em>., 2009). Ayam yang bertahan hidup, pertumbuhan menjadi terhambat dan sering kali ditemukan infeksi sekunder seperti <em>Newcastle Disease</em>, <em>Coli Bacillosis </em>dan <em>Coccidiosis </em>(Muller <em>et al</em>., 2003).</p>\r\n\r\n<p>Wabah IBD akut yang disebabkan virus IBD klasik yang menyerang ayam pedaging umur &gt; 3 minggu ditandai dengan angka morbiditas yang tinggi namun secara klinis terlihat ada penyembuhan setelah 5 &ndash; 7 hari ayam sakit. Infeksi pada ayam yang mempunyai antibodi maternal menunjukkan gejala subklinis, namun lesi dapat diamati secara histopatologik (Lukert dan Saif, 2003)</p>\r\n\r\n<p><a href=\"http://localhost/spkayam/gambar/posting/gumboro.jpeg\"><img alt=\"\" src=\"http://localhost/spkayam/gambar/posting/gumboro.jpeg\" style=\"height:313px; width:429px\" /></a></p>\r\n\r\n<p><strong>DIAGNOSIS</strong></p>\r\n\r\n<p>Diagnosis penyakit gumboro (IBD) dapat ditegakkan berdasarkan pada gejala klinis, perubahan patologi anatomi dan histopatologi. Perubahan patologi yang patognomonik adalah perubahan yang ditemukan pada bursa <em>Fabricius. </em>Namun demikian, diagnosis gumboro (IBD) sebagai penyebab primer perlu ditunjang dengan teknik diagnosis yang lain karena gejala infeksi virus gumboro (IBD) mirip dengan ND atau penyakit lain penyebab imunosupresif. Hal ini bisa diatasi dengan pewarnaan imunohistokimia, untuk mendeteksi keberadaan antigen virus IBD pada organ bursa <em>Fabricius. </em>Antigen virus IBD dapat dideteksi 3 jam paska infeksi pada bagian korteks folikel limfoid bursa <em>Fabricius</em>. Antigen dapat dideteksi pada makrofag di dalam folikel bursa <em>Fabricius </em>dan pada sel epitel 96 jam paska infeksi (Oladele <em>et</em> <em>al</em>., 2009). Keberadaan antigen IBD pada bursa <em>Fabricius </em>berkorelasi positif dengan terjadinya lesi pada bursa <em>Fabricius </em>(Rautenschlein <em>et al</em>., 2005).</p>\r\n\r\n<p>Antigen virus IBD juga terdeteksi pada organ timus, limpa, secal tonsil, sel epitel tubulus dan glomerulus ginjal, lapisan mukosa dan glandula pada proventrikulus serta pada sel <em>Kupffer </em>pada hati (Oladele <em>et al</em>., 2009). Antigen virus IBD juga dapat dideteksi pada itik dan kalkun yang diinfeksi dengan virus IBD, namun demikian jumlah antigen yang dideteksi relatif lebih sedikit (Oladele <em>et al.</em>, 2009)</p>\r\n\r\n<p>Diagnosis penyakit gumboro (IBD) dapat juga dilakukan dengan cara mengisolasi virus yang diduga sebagai penyebab, yang ditumbuhkan pada telur ayam berembrio berumur 11 hari atau biakan jaringan, namun diperlukan waktu relatif lama dan tidak semua <em>strain </em>virus IBD dapat tumbuh di telur atau biakan jaringan. Teknik uji netralisasi virus dapat digunakan untuk mendeteksi IBD, dan dari hasil deteksi dapat dibedakan antara IBD klasik dan IBD varian (Oie, 2008). Sedangkan <em>Antigen-capture </em>ELISA dapat digunakan untuk membedakan antara IBD sangat virulen dengan IBD yang kurang patogen. Sementara itu, teknik RT-PCR dapat membedakan serotipe IBD, sedangkan subtipe IBD dapat dibedakan dengan <em>real-time </em>RT-PCR (Currie, 2002). Virus IBD dapat dideteksi pada jaringan yang telah dibuat sebagai blok parafin dengan <em>real time </em>RT-PCR dan hasilnya menunjukkan bahwa ada korelasi positif antara lesi dan hasil deteksi antigen (Hamoud dan Villegas, 2006).</p>\r\n\r\n<p><strong>PENYEBARAN</strong></p>\r\n\r\n<p>Penyebaran penyakit sudah sampai ke Indonesia pada tahun 1983, ketika ditemukan kasus di Sawangan, Bogor (Partadiredja <em>et al</em>., 1983). Pada periode tahun 1990-an, penyakit IBD telah menyebar ke berbagai wilayah di Indonesia dan hasil isolasi dan identifikasi menunjukkan bahwa hampir semua isolat yang diperoleh berkerabat dekat dengan virus <em>very</em> <em>virulent </em>IBD (vvIBDv) (Parede <em>et al</em>., 2003).</p>\r\n\r\n<p>Penularan penyakit gumboro dari satu ayam ke ayam lain sangat cepat dalam waktu singkat ( 18 - 36 jam) seluruh ayam dalam kandang dapat ketularan. Kematian terjadi pada hari ke-3 sampai ke-5. Penybaran benih-benih penyakit melalui makanan,air minum, alat-alat dan tempat-tempat yang tercemar oleh feces dan makanan yang dimuntahkan. Virus penyakit gumboro stabil dan resisten, dapat dipindahkan satu tempat ketempat yang lain oleh orang, alat-alat peternakan yang tercemar. Sebuah peternakan yang pernah terjangkit Virus gumboro, maka Virus ini akan tetap infektip dan berdiam dalam peternakan tersebut untuk waktu yang lama. Menurut penelitian virus gumboro dapat hidup sampai 122 hari. Tidak ada carrier (hewan yang sembuh dan mwngandung virus yang dapa6t ditularkan). Penyakit ini tidak dapat dipindahkan melalui telur yang ditetaskan dan diduga juga tidak dapat disebakan melalui udara.</p>\r\n\r\n<p>&nbsp;</p>\r\n', '<p><strong>Pencegahan &amp; Pengendalian</strong></p>\r\n\r\n<p>Usaha pencegahan dan pengendalian supaya gumboro tidak mewabah adalah:</p>\r\n\r\n<p>a.&nbsp;&nbsp; Melakukan sanitasi lingkungan secara berkala, dengan disinfektan.</p>\r\n\r\n<p>b.&nbsp;&nbsp; Memberikan kondisi nyaman pada ayam terutama pada masa brooder, suhu brooder&nbsp;sesuai dengan kebutuhan anak ayam. Disesuaikan&nbsp;juga kondisi lingkungan, apabila suhu lingkungan sangat panas suhu brooder bisa disesuaikan. Pemberian pakan berkualitas dan minum dengan vitamin elektrolit dan anti strees. Perlakuan anak kandang yang baik, karena apabila perlakuan tidak baik dapat mengakibatkan stress pada ayam, dengan stress dapat menurunkan system kekebalan tubuh.</p>\r\n\r\n<p>Pengendalian terhadap penyakit IBD yang efektif adalah dengan melakukan program vaksinasi yang teratur disertai dengan program biosekuritas, diikuti dengan deteksi titer antibodi untuk mengetahui keberhasilan vaksinasi dengan uji serum netralisasi atau ELISA (Oie, 2008)</p>\r\n\r\n<p><strong>1.&nbsp;&nbsp; Vaksinasi</strong></p>\r\n\r\n<p>Vaksinasi pada ayam pembibit merupakan langkah terpenting untuk mengendalikan gumboro (IBD), karena antibodi yang diproduksi induk akan diturunkan melalui telur kepada anak. Antibodi maternal dengan titer yang baik akan memproteksi ayam melawan penyakit gumboro (IBD). Sebagai contoh, program vaksinasi pada ayam petelur dapat dilakukan pada umur 12 sampai 15 hari dengan vaksin IBD aktif. Pada umur 30 &ndash; 33 hari dengan vaksin IBD aktif dan pada umur 85 hari dengan vaksin inaktif, serta pada umur 120 hari dengan vaksin inaktif (Butcher dan Milles, 2003). Vaksinasi ulang pada umur 38 &ndash; 40 minggu dengan vaksin inaktif perlu dilakukan jika ayam pembibit mempunyai titer antibodi yang rendah atau tidak seragam. Monitoring titer antibodi perlu dilakukan secara rutin untuk mengetahui apakah ayam telah memberikan respon yang baik atau untuk mengetahui aplikasi vaksin sudah dilakukan dengan benar atau belum.</p>\r\n\r\n<p>Pencegahan dan pengendalian penyakit IBD pada ayam pedaging komersial diperlukan untuk mencegah penyakit IBD yang bersifat klinis. Ada tiga kategori vaksin yang digolongkan berdasarkan patogenisitasnya yaitu; <em>mild, intermediate </em>dan <em>virulent</em>. Tipe vaksin IBD <em>intermediate </em>paling umum digunakan. Vaksin ini dapat menstimulasi ayam pedaging dalam memproduksi antibodi lebih awal dari pada tipe vaksin <em>mild</em>, tanpa menyebabkan kerusakan bursa <em>Fabricius </em>seperti pada tipe vaksin virulen (Oie, 2008). Waktu vaksinasi tergantung pada titer antibodi maternal pada anak ayam. Titer antibodi maternal yang tinggi akan menetralisasi virus yang berasal dari vaksin. Jadi hanya sedikit respon kekebalan aktif yang akan dihasilkan, sehingga ayam akan mudah terinfeksi penyakit karena antibodi menurun, dan vaksinasi kemungkinan menjadi tidak efektif jika ayam terkontaminasi dengan virus IBD lapang yang lebih virulen. Vaksinasi IBD pada embrio merupakan alternatif vaksinasi yang memberikan kelebihan dibandingkan dengan vaksinasi setelah menetas yang umum digunakan. Hal ini disebabkan karena pada vaksinasi <em>in</em> <em>ovo</em>, titer antibodi maternal tidak perlu dimonitor untuk menentukan kapan vaksinasi harus dilakukan. Selain itu, hasil penelitian menunjukkan bahwa vaksinasi <em>in</em> <em>ovo </em>dengan virus yang telah diatenuasikan tidak merusak bursa <em>Fabricius </em>dan dapat memberikan proteksi hingga 100% pada ayam yang ditantang pada umur 3 minggu (Moura <em>et al</em>., 2007). Meskipun vaksinasi menyebabkan perubahan HP pada organ bursa namun penyembuhan lebih cepat terjadi pada ayam yang divaksin <em>in ovo </em>daripada yang divaksin pascamenetas (Rautenschlein dan Haase, 2005). Namun, kelemahan vaksin ini adalah memerlukan alat vaksin masal dan ukuran telur yang seragam sehingga aplikasi vaksin tepat pada posisi yang diinginkan.</p>\r\n\r\n<p><strong>2.&nbsp;&nbsp; Biosekuritas</strong></p>\r\n\r\n<p>Selain vaksinasi pelaksanaan terhadap program biosekuritas yang juga merupakan faktor penting dalam meminimalkan kerugian akibat infeksi IBD. Cserep menyatakan bahwa pada peternakan yang bebas dari Gumboro subklinis akan mendapatkan keuntungan 25% lebih besar, dibandingkan pada peternakan yang ditemukan kasus gumboro subklinis (Cooper, 2011). Upaya untuk melaksanakan biosekuritas dengan melakukan desinfeksi terhadap orang, peralatan atau kendaraan yang melintas antar kandang pada ayam pedaging komersial perlu dikontrol sehingga berjalan efektif untuk menurunkan paparan dari agen infeksi. Fenol dan formaldehid telah terbukti efektif digunakan untuk desinfeksi kandang dan lingkungan yang terkontaminasi. Antibiotik dengan jumlah seminimal mungkin diberikan pada kasus gumboro (IBD) yang disertai infeksi sekunder oleh bakteri. Namun hal ini tidak disarankan pada kasus yang disertai dengan kerusakan ginjal yang sangat parah. Pemberian larutan elektrolit atau multivitamin sangat bermanfaat pada kasus penyakit yang berlangsung lama yang disertai penurunan nafsu makan. Ventilasi yang baik, suhu ruangan yang hangat dan air minum yang bersih akan mengurangi kematian. Setelah ayam dipanen, kandang harus dikosongkan dari semua unggas. Semua <em>litter</em>, sisa pakan harus dibuang, kandang harus dibersihkan dan didesinfeksi. Fumigasi perlu dilakukan menggunakan formaldehyde dan Kalium permanganat. Kandang harus dikosongkan minimal 3 minggu setelah dilakukan fumigasi, untuk dapat digunakan lagi.</p>\r\n\r\n<p>&nbsp;</p>\r\n\r\n<p><strong>KESIMPULAN</strong></p>\r\n\r\n<p>Penyakit gumboro (IBD) merupakan penyakit viral yang bersifat infeksius dan menular, menyebabkan efek imunosupresif. Kerugian ekonomi yang ditimbulkan sangat besar karena menyebabkan kegagalan program vaksinasi. Diagnosis dapat dilakukan berdasarkan perubahan patologik yang diperkuat dengan deteksi antigen virus dengan teknik IHK. Pencegahan dengan memberikan vaksinasi telah rutin dilakukan, namun kasus masih sering terjadi. Penggunaan vaksin yang potensial dan diberikan pada saat antibodi maternal sudah menurun atau dengan menggunakan vaksin <em>in</em> <em>ovo </em>yang saat ini sudah dapat ditemukan di pasaran, diharapkan dapat mengurangi kasus yang terjadi di lapangan. Sudah saatnya dibuat vaksin isolat lokal yang diharapkan lebih protektif dibandingkan dengan vaksin isolat luar, karena sesuai dengan virus yang ada di lapang.</p>\r\n', '07 Gumboro.jpg'),
(21, 'Salesma Ayam (Infectious Coryza)', '<p>Penyakit&nbsp;<em>coryza</em>&nbsp;sudah akrab di telinga para peternak.Tanda penyakit tersebut juga mudah dikenali baik oleh peternak skala kecil maupun besar.Nama lainnya adalah snot atau pilek yang menjadi ciri khasnya.Hampir semua jenis unggas mudah terserang penyakit ini, diantaranya ayam pedaging, petelur, buras (kampung), merpati, itik maupun puyuh.<em>Coryza</em>&nbsp;bisa menyerang ayam pada semua umur, khususnya mulai umur 3 minggu sampai masa produksi.</p>\r\n\r\n<p>Peternak seringkali hanya tahu bahwa&nbsp;<em>coryza</em>&nbsp;merupakan suatu penyakit pernapasan (dilihat dari tanda khasnya), padahal&nbsp;<em>coryza</em>&nbsp;juga menyebabkan penurunan produksi telur.Pada ayam pedaging, penyakit ini juga mengganggu pertumbuhan ayam sehingga ayam sulit mencapai berat standar. Kerugian yang lainnya ialah tingginya biaya pengobatan, ayam menjadi mudah terserang penyakit lain atau penyakit menjadi komplek sehingga penyakit semakin sulit diatasi (ayam disembuhkan) dan seringkali berakhir dengan kematian.</p>\r\n\r\n<p>Meskipun korisa tidak menyerang sistem reproduksi, bukan berarti tidak menyebabkan penurunan produksi telur.Penurunan nafsu makan menyebabkan nutrisi yang diperlukan tubuh tidak tercukupi sehingga produksi telur pun terganggu.Bahkan penurunan produksi dapat mencapai 10-40%.Akibat korisa, angka pengafkiran relatif tinggi serta terjadi peningkatan biaya untuk pengobatan.Pada ayam pedaging mengakibatkan pertumbuhan terganggu sehingga bobot badan tidak tercapai. Mencegah korisa pun bisa dibilang gampang-gampang susah. Hal ini terbukti berdasarkan hasil pemantauan tenaga lapangan Medion tahun 2007-2009, korisa selalu menduduki peringkat pertama pada ayam petelur.</p>\r\n\r\n<p><strong>ETIOLOGI</strong></p>\r\n\r\n<p>Penyakit Snot atau&nbsp;<em>coryza</em>&nbsp;disebabkan oleh bakteri&nbsp;<em>Haemophillus gallinarum</em>.<em>Coryza</em>&nbsp;Infeksi (<em>IC)</em>&nbsp;adalah penyakit infeksi bakteri menular pernafasan beberapa spesies burung. Penyebab penyakit adalah bakteri&nbsp;<em>Haemophilus paragallinarum</em>. Termasuk bakteri gram negatif&nbsp;dan non motil, bentuk batang pendek dan berukuran 1-3 x 0,4-0,8 um. Bakteri yang ganas mempunyai kapsul dan mengalami degenerasi dalam waktu 48-60 jam, dalam bentuk fragmen dan bentuk yang tidak teratur.Organisme penyebabnya diketemukan pertama kali oleh Beach pada tahun 1920 (Akoso, 1992).</p>\r\n\r\n<p>Serotipe yang diketahui yaitu serovar A, B dan C. strain Modesto (M) termasuk serovar C. Ketiga strain tersebut ada yang menguraikan sebagai serovar I, II, dan III, tetapi menurut penelitian terakhir bahwa serovar II dan III merupakan varian dari serovar I.</p>\r\n\r\n<p><strong>PATOGENESA</strong></p>\r\n\r\n<p>Ada 3 jenis antigen dalam bakteri ini yaitu lipopolisakarida yang diisolasi dari cairan supernatant biakan dari strain serovar A dan C. antigen polisakarida yang diisolasi dari strain serovar A dan C yang menyebabkan&nbsp;<em>hidropericardium</em>&nbsp;pada ayam. Antigenketiga adalah asam hialuronik mengandung kapsul yang menyebabkan gejala&nbsp;<em>coryza</em>.</p>\r\n\r\n<p><strong>E</strong><strong>PIDEMIOLOGI</strong></p>\r\n\r\n<p>Penyakit ini pertama kali dilaporkan oleh Beach pada tahun 1920 dan berhasil diisolasi pada tahun 1931 yang diberi nama&nbsp;<em>Bacillus hemoglobinophilus coryzae gallinarum</em>. Penyakit ini bersifat endemik&nbsp;di dunia. Di Indonesia ditemukan tersebar luas dan endemik.</p>\r\n\r\n<p><strong>JENIS UNGGAS TERSERANG</strong></p>\r\n\r\n<p>Ayam menjadi hospes utama penyakit ini.Unggas lainnya juga terserang seperti kuau, ayam mutiara, dan puyuh.Sedangkan kalkun, itik, burung merpati, gelatik dan gagak relative tahan.Semua umur ayam dapat terserang, umur 4 minggu sampai 3 tahun peka. Anak ayam berumur 3-7 hari dilaporkan tahan penyakit karena adanya antibody maternal.</p>\r\n\r\n<p><strong>E. </strong><strong>CARA PENULARAN</strong></p>\r\n\r\n<p>Bakteri&nbsp;<em>Haemophillus gallinarum</em>&nbsp;hanya dapat bertahan diluar induk semang tidak lebih dari lebih dari 12 jam. Penularan penyakit Snot atau&nbsp;<em>coryza</em>&nbsp;dapat melalui kontak langsung dengan hewan yang sakit juga dapat melalui udara, debu, pakan, air minum, petugas dan peralatan yang digunakan.</p>\r\n\r\n<p><strong>MORBIDITAS DAN MORTALITAS</strong></p>\r\n\r\n<p>Tingkat morbiditas tinggi sedangkan mortalitas rendah. Jika ada komplikasi penyakit lain seperti cacar ayam, CRD, IB, kolera unggas dan ILT mortalitas menjadi tinggi.</p>\r\n\r\n<p><strong>GEJALA UMUM</strong></p>\r\n\r\n<p>Masa inkubasi tidak diketahui dengan pasti. Secara percobaan berlangsung 24-48 jam setelah infeksi atau intra sinus dengan biakan bakteri atau eksudat. Lama berlangsungnya penyakit tergantung dari inokulum dan keganasan bakteri. Ayam terserang ditandai dengan gejala pernafasan yaitu:</p>\r\n\r\n<ol>\r\n	<li>Pengeluaran cairan air mata</li>\r\n	<li>Keluar lendir dari hidung, kental berwarna kekuningan dan berbau khas</li>\r\n	<li>Pembengkakan di daerah sinus infraorbitalis</li>\r\n	<li>Terdapat kerak dihidung</li>\r\n	<li>Napsu makan turun</li>\r\n	<li>Pertumbuhan menjadi lambat.</li>\r\n	<li>Kelopak matannya menjadi lengket.</li>\r\n	<li>Nanah pada mata berbau busuk yang dapat mengerak disekitar lubang hidung dan mengkeju disekitar lubang hidung dan sinus.</li>\r\n</ol>\r\n\r\n<p>Angka kematian dapat mencapai 50%, tetapi bila tanpa komplikasi dengan penyakit ikutan biasanya hanya mencapai 20% atau kurang (Akoso, 1992).</p>\r\n\r\n<p><strong>DIAGNOSA</strong></p>\r\n\r\n<p>Penyakit didiagnosa berdasarkan epidemiologi, gejala klinis, patologi, isolasi dan identifikasi penyakit. Berbagai uji serologis dapat digunakan seperti aglutinasi tabung atau plat, AGP dan HI. Dengan AGP dapat mendeteksi antibodi 2 minggu pascainfeksi atau pascavaksinasi kurang lebih 11 minggu.</p>\r\n\r\n<p><strong>DIAGNOSA BANDING</strong></p>\r\n\r\n<p>Penyakit ini dapat dikelirukan dengan beberapa penyakit seperti ND, CAA, IB, CRD, kolera unggas kronis, cacar unggas, defisiensi vitamin A yang mempunyai gejala klinis yang mirip dengan coryza.</p>\r\n\r\n<p><strong>CONTOH HEWAN YANG TERSERANG CORYZA</strong></p>\r\n\r\n<p>Ayam menjadi hospes utama penyakit ini. Unggas lainnya juga terserang seperti ayam mutiara, dan puyuh. Sedangkan kalkun, itik, burung merpati, gelatik dan gagak relatif&nbsp;tahan. Semua umur ayam dapat terserang, umur 4 minggu sampai 3 tahun peka. Anak ayam berumur 3-7 hari dilaporkan tahan penyakit karena adanya antibodi&nbsp;maternal.</p>\r\n\r\n<p><a href=\"http://localhost/spkayam/gambar/posting/08Snot.png\"><img alt=\"Penyakit Snot atau coryza\" src=\"http://localhost/spkayam/gambar/posting/08Snot.png\" style=\"height:208px; width:347px\" /></a></p>\r\n\r\n<p><strong>Ayam yang secara klinis telah terinfeksi menunjukkan Gejala sebagai berikut:</strong></p>\r\n\r\n<ol>\r\n	<li>Pengeluaran cairan air mata</li>\r\n	<li>Ayam terlihat ngantuk dengan sayapnya turun atau menggantung</li>\r\n	<li>Keluar lendir dari hidung, berwarna kekuningan dan berbau khas</li>\r\n	<li>Pembengkakan didaerah sinus infra orbital</li>\r\n	<li>&nbsp;Terdapat kerak dihidung dan Rongga hidung mengeluarkan lendir kental yang lengket dan&nbsp;&nbsp;berbau busuk.</li>\r\n	<li>Napsu makan dan minum menurun sehingga terjadi penurunan produksi.</li>\r\n	<li>Getah radang dalam&nbsp;<em>trachea</em>&nbsp;dan&nbsp;<em>bronchi</em>&nbsp;dapat menghasilkan bunyi ngorok.</li>\r\n	<li>Sering kali dibarengi diare dan ayam dapat menjadi kerdil.</li>\r\n</ol>\r\n\r\n<p><strong>Perubahan Pascamati</strong></p>\r\n\r\n<ol>\r\n	<li>Selaput lendir hidung dan sinus mengalami peradangan katar yang akut.</li>\r\n	<li>Peradangan katar selaput mata.</li>\r\n	<li>Busung bawah kulit pada muka dan tulang.</li>\r\n	<li>Radang paru dan radang kantung udara</li>\r\n</ol>\r\n\r\n<p><strong>Diagnosa</strong></p>\r\n\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Contoh penyakit berupa tampon nanah dari hidung dan mata serta potongan jaringan dari alat pernapasan terutama batang tenggorok dan cabang tenggorok dikirimkan ke laboratorium dalam keadaan segar dingin untuk pengasingan dan identifikasi bakteri. Bahan pemeriksaan ini hendaknya diambil dari kejadian penyakit yang baru untuk menghindari pencemaran oleh bakteri sekunder.</p>\r\n\r\n<p>Diagnosa banding (mempunyai kemiripan) dari penyakit&nbsp;<em>coryza</em>&nbsp;/ snot adalah Mikoplasmosis atau&nbsp;<em>Chronic Respiratory Disease (CRD),Swollen Head Syndrome (SHS)</em>&nbsp;dan&nbsp;<em>Infectious Laryngotracheitis (ILT).</em></p>\r\n', '<p><strong>PENGOBATAN</strong></p>\r\n\r\n<p>Pengobatan Snot yang diberikan adalah preparat sulfat seperti&nbsp;<em>sulfadimethoxine</em>&nbsp;atau&nbsp;<em>sulfathiazole.</em>&nbsp;Seorang penulis menyebutkan pengobatan tradisional juga dilakukan dengan memberikan susu bubuk yang dicampur dengan air dan dibentuk sebesar kelereng sesuai dengan bukaan mulut ayam dan diberikan 3 kali sehari. &nbsp;</p>\r\n\r\n<p>Sedangkan pengobatan tradisional lain yang dapat dilakukan adalah memberikan perasan tumbukan jahe, kunir, kencur dan lempuyang. Air perasan ini dicampurkan pada air minum.Selain ramuan ini menghangatkan tubuh ayam, ramuan ini juga berkhasiat untuk menambah napsu makan ayam. Selain memberikan obat yang diberikan bersama dengan air minum, juga diberikan obat secara suntikan pada ayam yang sudah parah. Obat yang diberikan adalah Sulfamix dengan dosis 0.4 cc/kg bobot badan ayam. Hal lain yang perlu dilakukan karena penyakit ini mempunyai penularan yang sangat cepat dan luas, ayam yang terkena Snot harus sesegera mungkin dipisahkan dari kelompoknya.&nbsp;Belakangan ini telah dikembangkan vaksin&nbsp;<em>coryza</em>&nbsp;yang dikembangkan dengan vaksin IB dan ND inaktif.</p>\r\n\r\n<p><strong>Pencegahan</strong></p>\r\n\r\n<ol>\r\n	<li>Ayam yang sakit pilek dipisahkan dari kandang (kelompok) ayam yang sehat.</li>\r\n	<li>Jangan mencampur ayam yang umurnya berbeda.</li>\r\n	<li>Kandang dan lingkungan harus selalu dalam keadaan bersih.</li>\r\n	<li>Usahakan dalam kandang terkena sinar matahari.</li>\r\n</ol>\r\n\r\n<p><strong>Perlakuan dalam Pemotongan</strong></p>\r\n\r\n<p>Ayam yang sakit pilek dapat dipotong dan dagingnya boleh dikonsumsi.Bangkai ayam yang mati dan sisa pemotongan dibakar atau dikubur.</p>\r\n\r\n<p><strong>Pengobatan</strong></p>\r\n\r\n<p>Obat kimia yang bisa digunakan antara lain:</p>\r\n\r\n<ol>\r\n	<li>Sulfatiasol.</li>\r\n	<li>Sulfadimetoksin.</li>\r\n	<li>Streptomisin.</li>\r\n	<li>Sulfametasin.</li>\r\n	<li>Sulfamerasin.</li>\r\n	<li>Eritromisin.</li>\r\n	<li>Vibravet&nbsp;<em>(soluble powder)</em>&nbsp;dengan takaran 4 gram dicampur 1 liter air minum, diberikan 4-5 hari.</li>\r\n</ol>\r\n\r\n<p>Ramuan jamu tradisional yang dapat digunakan:</p>\r\n\r\n<ol>\r\n	<li>Tepung beras padi 150 gram.</li>\r\n	<li>Kencur 100 gram, ditumbuk halus.</li>\r\n	<li>Jahe sebanyak 25 gram atau kurang lebih 1 jari tangan, diparut.</li>\r\n	<li>Bahan tersebut digilas dengan pipisan (lumpang) hingga halus dan tercampur merata.</li>\r\n	<li>Ramuan ini dibentuk pil sebesar biji jagung, lalu dijemur hingga kering.</li>\r\n	<li>Pil disuapkan dua kali sehari (pagi dan sore)</li>\r\n</ol>\r\n', '08 Snot.jpg'),
(22, 'Batuk Ayam Menahun (Infectious Bronchitis)', '<p>Unggas merupakan salah satu sumber protein hewani baik berupa telur maupun daging untuk menunjang kebutuhan protein masyarakat Indonesia. Peternakan unggas, terutama ayam amat berperan dan perlu senantiasa ditingkatkan kinerjanya, agar dapat berproduksi secara optimal. Salah satu faktor yang perlu mendapat perhatian adalah kesehatan ternak, karena produksi yang optimal hanya akan dapat dicapai bila keadaan ternaknya sehat. Namun demikian, untuk mencapai tujuan tersebut tidaklah mudah, karena masih terdapat kendala berupa penyakit, di antaranya adalah penyakit yang disebabkan oleh virus seperti penyakit <em>infectious bronchitis </em>(IB).</p>\r\n\r\n<p>Infectious Bronchitis (IB) adalah penyakit saluran pernafasan pada ayam yang disebabkan oleh virus, bersifat akut dan sangat menular sehingga penyebarannya dalam kelompok ayam sangat cepat sekali, dan ditandai dengan sesak nafas pada ayam dan penurunan produksi yang tajam pada ayam petelur. Penyakit IB ini sangat merugikan. Angka kematian pada ayam muda berkisar antara 0 &ndash; 40%, kematian yang tertinggi pada ayam berumur kurang dari 6 minggu sedang derajat pertumbuhannya sangat terlambat, sehingga penyakit ini sangat merugikan peternakan ayam pedaging. Pada ayam dewasa angka kematiaanya berkisar antara 0 &ndash; 5%, dan mengakibatkan penurunan produksi telur yang sangat cepat. Penurunan produksi telur ini dapat berlangsung dalam waktu yang cukup lama, bahkan ada kalanya kelompok ayam yang bersangkutan tidak dapat kembali berproduksi setingkat dengan produksi semula.</p>\r\n\r\n<p><strong>ETIOLOGI</strong></p>\r\n\r\n<p>Penyakit IB disebabkan oleh virus IB yang termasuk ke dalam famili <em>Coronaviridae </em>dan hanya memiliki satu genus, yaitu <em>Coronavirus</em>. Virus IB berbentuk <em>pleomorphic</em>, memiliki <em>envelop </em>(selaput luar) dengan diameter 90 &ndash; 200 nm, serta memiliki asam inti berutas tunggal asam ribonukleat (RNA) dengan berat molekul 8 x 106 <em>Base</em> <em>pair </em>(Bp). Virus IB mudah tumbuh dalam embrio ayam, sedang dalam biakan jaringan hanya dapat tumbuh setelah mengalami adaptasi. Bila berada di luar tubuh ayam virus IB akan segera in aktif, terutama bila terkena panas atau sinar matahari.</p>\r\n\r\n<p>Berdasarkan sifat kimia dan fisiknya, virus IB sangat labil dan sensitif terhadap bahan-bahan yang bersifat <em>lipolitik </em>(seperti ether dan chlorofrom), panas, dan berbagai bahan disinfektan (Otsuki <em>et al.</em>, 1979). Virus IB umumnya dapat diinaktif dengan menempatkannya pada suhu 56&deg;C selama 15 menit dan 45&deg;C selama 90 menit. Virus lebih lama bertahan pada pH 11 daripada pH 3 (Alexander dan Collins, 1975). Ayam yang terinfeksi virus dalam organ dapat terpelihara dengan baik dalam 50% glyserin NaCl physiologis. Sifat yang demikian memungkinkan pengiriman sampel ke laboratorium tanpa pendingin (Hofstad, 1984). Isolat virus IB dapat bertahan selama beberapa tahun bila disimpan pada suhu -30&deg;C (Hofstad, 1984).</p>\r\n\r\n<p><strong>GEJALA KLINIK</strong></p>\r\n\r\n<p>Pada ayam muda penyakit IB menyebar sangat cepat dan menulari semua ayam dalam kelompok. Dari hidung keluar lendir, sesak nafas dan ngorok. Mata terlihat selalu basah. Nafsu makan dan minum menurun. Anak ayam di bawah umur tiga minggu yang terinfeksi penyakit IB memperlihatkan gejala, kesulitan bernafas, ngorok, batuk batuk, bersin dan mata basah (Hofstad, 1984), serta keterlambatan pertumbuhan bobot badan pada ayam <em>broiler </em>(Davelaar <em>et al</em>., 1986). Pada ayam petelur dewasa penyakit IB menampakan gejala penurunan produksi telur hingga mencapai 60% dalam kurun waktu 6 &ndash; 7 minggu dan selalu disertai dengan penurunan mutu telur, seperti bentuk telur tak teratur, kerabang telur lunak dan albumin telur cair.</p>\r\n\r\n<p>Patologi anatomi pada ayam yang diduga terserang virus IB terlihat adanya cairan encer, agak encer hingga kental di dalam trachea, saluran hidung dan sinus hidung, pada kantong udara berwarna keruh atau mengandung eksudat berwarna kuning dan sedikit peradangan di sekitar bronchi (Hofstad, 1984). Sementara itu, perubahan anatomi pada ayam yang terserang virus IB yang bersifat <em>nephrohepatic </em>terlihat adanya pembengkakan dan berwarna pucat pada ginjal dengan tubulus dan ureter berisi asam urat (Cumming, 1972). Pengukuhan diagnosis IB dengan pemeriksaan sampel ayam atau organ, trachea, ginjal, dan ovarium yang diduga terserang IB, dikirim ke laboratorium dalam keadaan segar untuk pemeriksaan <em>immuno-</em> <em>fluorescent </em>(Chubb, 1986 dan Hawkes <em>et al., </em>1983) atau <em>immunoperoxidase </em>(Nagi, 1990). Selain cara di atas pemeriksaan patologik anatomi dan histopatologik, dikukuhkan dengan isolasi virus dan bila memungkinkan penentuan serotipe virus IB (Cavanagh dan Nagi, 1997).</p>\r\n\r\n<p><strong>CARA PENULARAN</strong></p>\r\n\r\n<p>Penyakit ini cepat menular diantara ayam dalam satu kelompok. Umumnya penularan terjadi melalui pernafasan. Virus terutama dikeluarkan dari saluran pernafasan dan ginjal. Virus akan menyebar dari satu peternakan ke peternakan lain melalui udara sehingga penularan dalam jarak 1100 meter dapat terjadi. Faktor predisposisi yang memperburuk kondisi ayam yang terinfeksi IB adalah infeksi dari Mycoplasma gallisepticum. Bila virus IB menulari sekelompok ayam yang rentan maka dalam waktu 2 atau 3 hari seluruh ayam dalam kelompok tadi akan tertular IB walaupun ayam berada dalam kandang yang memenuhi persyaratan sanitasi.</p>\r\n\r\n<p><strong>DIAGNOSA BANDING</strong></p>\r\n\r\n<ol>\r\n	<li>Avian Influenza</li>\r\n	<li>Infectious Coryza</li>\r\n	<li>Infectious Laryngotracheitis</li>\r\n	<li>Newcastle Disease</li>\r\n</ol>\r\n\r\n<p>Catatan: Tanda-tanda klinis penyakit Avian Infeksious Bronchitis (IB) dapat menyerupai penyakit pernapasan akut lainnya pada ayam, seperti penyakit Newcastle Disease (ND), Infeksius Laringotrakeitis (ILT), flu burung /Avian Infuenza (HPAI) dan infeksius coryza /Snot. Pengujian laboratorium diperlukan untuk membedakan infeksi ini. Pada penyakit IB, cairan allantoic dari embrio terinokulasi tidak menghemagglutinasi eritrosit. Untuk virus penyakit Newcastle Disease (ND), dan virus flu burung /Avian Influenza (HPAI), cairan allantoic dari embrio terinokulasi akan positif untuk hemaglutinasi.</p>\r\n\r\n<p><strong>DIAGNOSA LABORATORIUM</strong></p>\r\n\r\n<p><a href=\"http://2.bp.blogspot.com/-e09xbOgRdMw/VLY3bPYfGDI/AAAAAAAAA6U/topaT8LifFY/s1600/PENYAKIT%2BINFECTIOUS%2BBRONCHITIS.jpg\"><img src=\"http://2.bp.blogspot.com/-e09xbOgRdMw/VLY3bPYfGDI/AAAAAAAAA6U/topaT8LifFY/s1600/PENYAKIT%2BINFECTIOUS%2BBRONCHITIS.jpg\" style=\"height:207px; width:320px\" /></a></p>\r\n\r\n<p>Di laboratorium dilakukan isolasi virus dengan jalan membiakkannyadi dalam embrio ayam. Pada embrio ini perlu diadakan pasase seri sebanyak 4 atau 5 kali sampai ditemukan kelainan pada embrio, yaitu kekerdilan dan kemerahan. Sediaan guna pemeriksaan Fluorescent Antibody Test (FAT) disiapkan dari embrio yang kerdil tersebut. Sediaan ini dilihat di bawah mikroskop flueresen. Sediaan guna pemeriksaan FAT dapat langsung dibuat dari tralhea atau paru-paru tersangka. Hasil diagnose akan segera didapat pada hari itu juga. Untuk pemeriksaan FAT material dapat dikirim ke FKH-IPB, BPPH Medan, BPPH Ujung Pandang, BPPH Denpasar dll. Uji netralisasi serum dalam telur tertunas atau dalam biakan jaringan dapat dilakukan guna identifikasi virus. Dengan cara ini hasil diagnose akan memakan waktu yang lebih lama.</p>\r\n', '<p><strong>Pencegahan &amp; Pemberantasan</strong></p>\r\n\r\n<p>Dalam upaya pencegahan penyakit IB perlu diperhatikan beberapa faktor, seperti sanitasi, imunitas, aplikasi vaksinasi dan pemantauan terhadap kekebalan ayam, sehingga ayam terhindar dari serangan penyakit IB yang merugikan. Ayam yang sakit atau mati disingkirkan dan dimusnahkan dengan cara dibakar atau dikubur dalam-dalam. Cara efektif adalah melakukan vaksinasi dengan vaksin aktif atau inaktif.</p>\r\n\r\n<p>Vaksin aktif digunakan sebagai vaksin primer pada ayam broiler dan petelur, sedangkan vaksin mati dalam emulsi minyak digunakan sebagai vaksin ulangan (booster). Aplikasi vaksin dapat diberikan melalui tetes mata, intratrachea atau intranasal. Vaksinasi pada umur 1 atau 2 hari dilaporkan memberikan respon kekebalan pada ayam. Jadwal vaksinasi berikutnya dilakukan pada umur 7-12 atau 6-16 minggu.</p>\r\n', '09 IB.jpg');

